def _safe_variant_slug(value: Any) -> str:
    raw = str(value or "").strip().lower()
    chars: list[str] = []
    previous_separator = False
    for char in raw:
        if char.isalnum():
            chars.append(char)
            previous_separator = False
        elif char in {"_", "-", " ", "/", "."} and not previous_separator:
            chars.append("_")
            previous_separator = True
    slug = "".join(chars).strip("_")
    return slug or "unknown"


def _deferred_variant_activation_unlock_plan(
    report: dict[str, Any],
    *,
    activation_gates: list[dict[str, Any]],
    activation_blockers: list[str],
) -> dict[str, Any]:
    history_depth_runway = _exact_profitability_history_depth_runway(report)
    replay_unlock_contract = (
        report.get("exact_replay_unlock_contract")
        if isinstance(report.get("exact_replay_unlock_contract"), dict)
        else build_exact_replay_unlock_contract(report)
    )
    replay_unlock_summary = {
        "status": replay_unlock_contract.get("status"),
        "diagnostic_remaining_shared_quote_dates": replay_unlock_contract.get(
            "diagnostic_remaining_shared_quote_dates"
        ),
        "full_remaining_shared_quote_dates": replay_unlock_contract.get("full_remaining_shared_quote_dates"),
        "diagnostic_unlock_trade_date": replay_unlock_contract.get("diagnostic_unlock_trade_date"),
        "full_unlock_trade_date": replay_unlock_contract.get("full_unlock_trade_date"),
        "immediate_next_capture_command": replay_unlock_contract.get("immediate_next_capture_command"),
        "immediate_next_capture_not_before_user_local": replay_unlock_contract.get(
            "immediate_next_capture_not_before_user_local"
        ),
        "replay_command_when_unlocked": replay_unlock_contract.get("replay_command_when_unlocked"),
        "blockers": replay_unlock_contract.get("blockers"),
    }
    gate_unlocks: list[dict[str, Any]] = []
    for gate in activation_gates:
        if not isinstance(gate, dict):
            continue
        name = str(gate.get("name") or "")
        base = {
            "gate": name,
            "passed": gate.get("passed") is True,
            "actual": gate.get("actual"),
            "expected": gate.get("expected"),
        }
        if name == "enough_exact_shared_quote_dates":
            gate_unlocks.append(
                {
                    **base,
                    "unlock_source": "exact_profitability_history_depth_runway",
                    "blocking_goal_requirement": "has_required_exact_alpaca_opra_history_depth",
                    "unblock_when": "current_shared_quote_dates >= required_shared_quote_dates",
                    "next_evidence_action": "continue_forward_daily_alpaca_opra_capture",
                    "current_shared_quote_dates": history_depth_runway.get("current_shared_quote_dates"),
                    "required_shared_quote_dates": history_depth_runway.get("required_shared_quote_dates"),
                    "remaining_shared_quote_dates": history_depth_runway.get("remaining_shared_quote_dates"),
                    "next_capture_trade_date": history_depth_runway.get("next_capture_trade_date"),
                    "next_capture_not_before_user_local": history_depth_runway.get(
                        "next_capture_not_before_user_local"
                    ),
                    "next_capture_command": history_depth_runway.get("next_capture_command"),
                    "diagnostic_unlock_trade_date": history_depth_runway.get("diagnostic_unlock_trade_date"),
                    "full_replay_unlock_trade_date": history_depth_runway.get("full_replay_unlock_trade_date"),
                    "next_capture_effect": history_depth_runway.get("next_capture_effect"),
                }
            )
        elif name == "readiness_ready_for_exact_replay":
            gate_unlocks.append(
                {
                    **base,
                    "unlock_source": "exact_replay_unlock_contract",
                    "blocking_goal_requirement": "has_required_exact_alpaca_opra_history_depth",
                    "unblock_when": "full_exact_replay_unlocked true and readiness status ready_for_exact_replay",
                    "next_evidence_action": replay_unlock_contract.get("next_action")
                    or "continue_forward_daily_alpaca_opra_capture",
                    "replay_unlock_status": replay_unlock_contract.get("status"),
                    "full_remaining_shared_quote_dates": replay_unlock_contract.get(
                        "full_remaining_shared_quote_dates"
                    ),
                    "full_unlock_trade_date": replay_unlock_contract.get("full_unlock_trade_date"),
                    "replay_command_when_unlocked": replay_unlock_contract.get("replay_command_when_unlocked"),
                }
            )
        elif name in {"exact_replay_completed", "exact_replay_has_trades"}:
            gate_unlocks.append(
                {
                    **base,
                    "unlock_source": "exact_replay_unlock_contract",
                    "blocking_goal_requirement": "exact_replay_is_profitable",
                    "unblock_when": "run exact replay after full Alpaca OPRA history depth is unlocked",
                    "next_evidence_action": "run_full_exact_replay_profitability_gate",
                    "replay_unlock_status": replay_unlock_contract.get("status"),
                    "full_unlock_trade_date": replay_unlock_contract.get("full_unlock_trade_date"),
                    "replay_command_when_unlocked": replay_unlock_contract.get("replay_command_when_unlocked"),
                }
            )
        else:
            gate_unlocks.append(
                {
                    **base,
                    "unlock_source": "activation_gate",
                    "unblock_when": "gate passes in current exact Alpaca OPRA report",
                }
            )
    primary_gate = activation_blockers[0] if activation_blockers else None
    return {
        "status": (
            "ready_to_start_deferred_variants"
            if not activation_blockers
            else "locked_until_exact_opra_history_and_replay_gates_pass"
        ),
        "safe_to_start_now": not activation_blockers,
        "current_primary_gate": primary_gate,
        "activation_blockers": activation_blockers,
        "history_depth_runway": history_depth_runway,
        "replay_unlock_contract": replay_unlock_summary,
        "gate_unlocks": gate_unlocks,
        "next_capture_command": history_depth_runway.get("next_capture_command"),
        "next_capture_not_before_user_local": history_depth_runway.get("next_capture_not_before_user_local"),
        "diagnostic_unlock_trade_date": history_depth_runway.get("diagnostic_unlock_trade_date"),
        "full_replay_unlock_trade_date": history_depth_runway.get("full_replay_unlock_trade_date"),
        "next_action": (
            "materialize_variant_configs_and_run_exact_opra_sweeps"
            if not activation_blockers
            else "follow_exact_profitability_history_depth_runway_until_activation_gates_pass"
        ),
        "variant_work_policy": "deferred_variant_materialization_and_sweeps_remain_locked_until_safe_to_start_now_true",
    }


def _deferred_variant_run_recipes(
    *,
    drop_key: str,
    blueprint: dict[str, Any],
    activation_blockers: list[str],
    activation_unlock_plan: dict[str, Any],
) -> list[dict[str, Any]]:
    recipes: list[dict[str, Any]] = []
    history_depth_runway = (
        activation_unlock_plan.get("history_depth_runway")
        if isinstance(activation_unlock_plan.get("history_depth_runway"), dict)
        else {}
    )
    replay_unlock_contract = (
        activation_unlock_plan.get("replay_unlock_contract")
        if isinstance(activation_unlock_plan.get("replay_unlock_contract"), dict)
        else {}
    )
    blocked_by_goal_requirements = list(
        dict.fromkeys(
            str(gate.get("blocking_goal_requirement"))
            for gate in (activation_unlock_plan.get("gate_unlocks") or [])
            if isinstance(gate, dict)
            and gate.get("passed") is not True
            and gate.get("blocking_goal_requirement")
        )
    )
    first_blocking_gate = activation_blockers[0] if activation_blockers else None
    activation_ready_not_before_user_local = (
        history_depth_runway.get("full_replay_unlock_not_before_user_local")
        or replay_unlock_contract.get("full_unlock_not_before_user_local")
    )
    activation_ready_trade_date = (
        history_depth_runway.get("full_replay_unlock_trade_date")
        or replay_unlock_contract.get("full_unlock_trade_date")
    )
    next_unlock_command = (
        history_depth_runway.get("next_capture_command")
        or replay_unlock_contract.get("immediate_next_capture_command")
        or replay_unlock_contract.get("replay_command_when_unlocked")
    )
    variant_family = _safe_variant_slug(blueprint.get("variant_family") or drop_key)
    drop_slug = _safe_variant_slug(drop_key or variant_family)
    for draft in list(blueprint.get("draft_variants") or []):
        if not isinstance(draft, dict) or not draft.get("id"):
            continue
        variant_id = _safe_variant_slug(draft.get("id"))
        if not variant_id:
            continue
        config_id = f"ai_commodity_infra_{variant_family}_{variant_id}"
        run_slug = f"{config_id}-exact-opra"
        config_path = f"{DEFERRED_VARIANT_CONFIG_ROOT}/{config_id}.json"
        variant_config: dict[str, Any] = {
            "id": config_id,
            "lane_id": DEFERRED_VARIANT_PLAYBOOK,
            "drop_key": drop_slug,
            "variant_id": variant_id,
            "research_only": True,
            "provider": "alpaca:sip:opra",
            "proof_source_label": ALPACA_OPRA_SOURCE_LABEL,
            "purpose": draft.get("purpose"),
            "risk_to_measure": draft.get("risk_to_measure"),
            "minimum_promotion_evidence": _minimum_exact_variant_promotion_evidence(),
        }
        for override_key in (
            "profile_overrides",
            "ai_commodity_option_filter_overrides",
            "playbook_overrides",
        ):
            overrides = draft.get(override_key)
            if overrides:
                variant_config[override_key] = overrides
        command_args = [
            "python",
            "scripts/run_research_variant_cycle.py",
            "--variant-config",
            config_path,
            "--",
            "--slug",
            run_slug,
            "--proposal",
            DEFERRED_VARIANT_PROPOSAL_PATH,
            "--mode",
            "search",
            "--allow-phase-override",
            "--playbook",
            DEFERRED_VARIANT_PLAYBOOK,
            "--truth-lane",
            DEFERRED_VARIANT_TRUTH_LANE,
            "--require-quote-coverage",
            DEFERRED_VARIANT_REQUIRED_QUOTE_COVERAGE,
        ]
        recipes.append(
            {
                "variant_id": variant_id,
                "run_slug": run_slug,
                "status": "ready_after_exact_replay" if not activation_blockers else "queued_locked",
                "variant_config_path": config_path,
                "variant_config": variant_config,
                "variant_config_write_status": "not_written_by_progress_report",
                "write_guard": "write_only_after_activation_gates_pass",
                "config_materialization_status": "not_written_by_progress_report",
                "config_materialization_action": "write_variant_config_json_to_variant_config_path_after_activation_gates_pass",
                "run_command_args": command_args,
                "run_command": " ".join(command_args),
                "run_guard": "do_not_run_until_all_activation_gates_pass",
                "blocked_by": activation_blockers,
                "first_blocking_gate": first_blocking_gate,
                "blocked_by_goal_requirements": blocked_by_goal_requirements,
                "activation_status": (
                    "ready_to_materialize_and_run"
                    if not activation_blockers
                    else "locked_until_activation_gates_pass"
                ),
                "activation_ready_trade_date": activation_ready_trade_date,
                "activation_ready_not_before_user_local": activation_ready_not_before_user_local,
                "next_unlock_command": next_unlock_command,
                "next_unlock_not_before_user_local": (
                    history_depth_runway.get("next_capture_not_before_user_local")
                    or replay_unlock_contract.get("immediate_next_capture_not_before_user_local")
                ),
                "replay_command_when_unlocked": replay_unlock_contract.get("replay_command_when_unlocked"),
                "activation_unlock_plan": activation_unlock_plan,
                "expected_evidence_artifacts": [
                    f"research_runs/<timestamp>_{run_slug}/manifest.json",
                    f"research_runs/<timestamp>_{run_slug}/primary_report.json",
                ],
                "compare_fields": [
                    "verification_gate.replay_total_trades",
                    "verification_gate.replay_profit_factor",
                    "verification_gate.replay_total_return_pct",
                    "scan.candidate_count",
                    "scan.candidate_symbols",
                ],
            }
        )
    return recipes


def _arg_value(args: list[str], flag: str) -> str | None:
    try:
        index = args.index(flag)
    except ValueError:
        return None
    next_index = index + 1
    if next_index >= len(args):
        return None
    return args[next_index]


def _deferred_variant_recipe_audit(
    *,
    deferred_test_queue: list[dict[str, Any]],
    activation_blockers: list[str],
) -> dict[str, Any]:
    recipe_audits: list[dict[str, Any]] = []
    for queue_item in deferred_test_queue:
        drop_key = str(queue_item.get("drop_key") or "")
        for recipe in list(queue_item.get("variant_run_recipes") or []):
            if not isinstance(recipe, dict):
                continue
            variant_config = recipe.get("variant_config") if isinstance(recipe.get("variant_config"), dict) else {}
            args = [str(item) for item in list(recipe.get("run_command_args") or [])]
            has_override_payload = any(
                bool(variant_config.get(key))
                for key in ("profile_overrides", "ai_commodity_option_filter_overrides", "playbook_overrides")
            )
            checks = [
                {
                    "name": "provider_is_alpaca_sip_opra",
                    "passed": variant_config.get("provider") == "alpaca:sip:opra",
                    "actual": variant_config.get("provider"),
                    "expected": "alpaca:sip:opra",
                },
                {
                    "name": "proof_source_is_alpaca_opra_daily_snapshot",
                    "passed": variant_config.get("proof_source_label") == ALPACA_OPRA_SOURCE_LABEL,
                    "actual": variant_config.get("proof_source_label"),
                    "expected": ALPACA_OPRA_SOURCE_LABEL,
                },
                {
                    "name": "runner_is_research_variant_cycle",
                    "passed": "scripts/run_research_variant_cycle.py" in args,
                    "actual": args[1] if len(args) > 1 else None,
                    "expected": "scripts/run_research_variant_cycle.py",
                },
                {
                    "name": "playbook_is_ai_commodity_observation",
                    "passed": variant_config.get("lane_id") == DEFERRED_VARIANT_PLAYBOOK
                    and _arg_value(args, "--playbook") == DEFERRED_VARIANT_PLAYBOOK,
                    "actual": {
                        "variant_config_lane_id": variant_config.get("lane_id"),
                        "command_playbook": _arg_value(args, "--playbook"),
                    },
                    "expected": DEFERRED_VARIANT_PLAYBOOK,
                },
                {
                    "name": "truth_lane_is_historical_imported_daily",
                    "passed": _arg_value(args, "--truth-lane") == DEFERRED_VARIANT_TRUTH_LANE,
                    "actual": _arg_value(args, "--truth-lane"),
                    "expected": DEFERRED_VARIANT_TRUTH_LANE,
                },
                {
                    "name": "quote_coverage_required_95",
                    "passed": _arg_value(args, "--require-quote-coverage")
                    == DEFERRED_VARIANT_REQUIRED_QUOTE_COVERAGE,
                    "actual": _arg_value(args, "--require-quote-coverage"),
                    "expected": DEFERRED_VARIANT_REQUIRED_QUOTE_COVERAGE,
                },
                {
                    "name": "has_research_override_payload",
                    "passed": has_override_payload,
                    "actual": has_override_payload,
                    "expected": True,
                },
                {
                    "name": "write_guard_blocks_materialization_until_activation",
                    "passed": recipe.get("write_guard") == "write_only_after_activation_gates_pass",
                    "actual": recipe.get("write_guard"),
                    "expected": "write_only_after_activation_gates_pass",
                },
                {
                    "name": "run_guard_blocks_until_activation",
                    "passed": recipe.get("run_guard") == "do_not_run_until_all_activation_gates_pass",
                    "actual": recipe.get("run_guard"),
                    "expected": "do_not_run_until_all_activation_gates_pass",
                },
            ]
            recipe_audits.append(
                {
                    "drop_key": drop_key,
                    "variant_id": recipe.get("variant_id"),
                    "status": recipe.get("status"),
                    "activation_status": recipe.get("activation_status"),
                    "variant_config_path": recipe.get("variant_config_path"),
                    "blocked_by": recipe.get("blocked_by") or [],
                    "first_blocking_gate": recipe.get("first_blocking_gate"),
                    "blocked_by_goal_requirements": recipe.get("blocked_by_goal_requirements") or [],
                    "activation_ready_trade_date": recipe.get("activation_ready_trade_date"),
                    "activation_ready_not_before_user_local": recipe.get(
                        "activation_ready_not_before_user_local"
                    ),
                    "next_unlock_command": recipe.get("next_unlock_command"),
                    "passed": all(check.get("passed") is True for check in checks),
                    "checks": checks,
                }
            )
    recipe_count = len(recipe_audits)
    failed_recipes = [item for item in recipe_audits if item.get("passed") is not True]
    locked_recipe_count = sum(1 for item in recipe_audits if item.get("status") == "queued_locked")
    ready_to_run_count = sum(1 for item in recipe_audits if item.get("status") == "ready_after_exact_replay")
    all_recipes_opra_backed = all(
        any(check.get("name") == "provider_is_alpaca_sip_opra" and check.get("passed") is True for check in item["checks"])
        and any(
            check.get("name") == "proof_source_is_alpaca_opra_daily_snapshot" and check.get("passed") is True
            for check in item["checks"]
        )
        for item in recipe_audits
    )
    all_recipes_guarded = all(
        any(
            check.get("name") == "write_guard_blocks_materialization_until_activation"
            and check.get("passed") is True
            for check in item["checks"]
        )
        and any(check.get("name") == "run_guard_blocks_until_activation" and check.get("passed") is True for check in item["checks"])
        for item in recipe_audits
    )
    if recipe_count == 0:
        status = "no_deferred_variant_recipes"
    elif failed_recipes:
        status = "recipe_contract_failed"
    elif activation_blockers:
        status = "queued_locked_with_verified_opra_recipe_contracts"
    else:
        status = "ready_with_verified_opra_recipe_contracts"
    return {
        "status": status,
        "recipe_count": recipe_count,
        "locked_recipe_count": locked_recipe_count,
        "ready_to_run_count": ready_to_run_count,
        "all_recipes_opra_backed": all_recipes_opra_backed,
        "all_recipes_guarded": all_recipes_guarded,
        "safe_to_run_now": bool(recipe_count) and not activation_blockers and not failed_recipes,
        "activation_blockers": activation_blockers,
        "failed_recipe_count": len(failed_recipes),
        "failed_recipes": failed_recipes,
        "recipes": recipe_audits,
        "variant_config_root": DEFERRED_VARIANT_CONFIG_ROOT,
        "materialization_command": "python scripts/run_ai_commodity_opra_progress.py --materialize-deferred-variant-configs",
        "materialization_dry_run_command": (
            "python scripts/run_ai_commodity_opra_progress.py --materialize-deferred-variant-configs "
            "--materialize-dry-run"
        ),
        "next_action": (
            "wait_for_activation_gates_then_materialize_configs"
            if activation_blockers
            else "materialize_variant_configs_and_run_exact_opra_sweeps"
        ),
    }


def _deferred_variant_execution_plan(
    *,
    deferred_test_queue: list[dict[str, Any]],
    recipe_audit: dict[str, Any],
    activation_blockers: list[str],
    activation_unlock_plan: dict[str, Any],
) -> dict[str, Any]:
    ordered_sweeps: list[dict[str, Any]] = []
    for queue_item in deferred_test_queue:
        if not isinstance(queue_item, dict):
            continue
        for recipe_index, recipe in enumerate(list(queue_item.get("variant_run_recipes") or []), start=1):
            if not isinstance(recipe, dict):
                continue
            ordered_sweeps.append(
                {
                    "sequence": len(ordered_sweeps) + 1,
                    "queue_rank": queue_item.get("rank"),
                    "drop_key": queue_item.get("drop_key"),
                    "variant_id": recipe.get("variant_id"),
                    "run_slug": recipe.get("run_slug"),
                    "variant_config_path": recipe.get("variant_config_path"),
                    "variant_config_write_status": recipe.get("variant_config_write_status"),
                    "run_command": recipe.get("run_command"),
                    "run_command_args": recipe.get("run_command_args"),
                    "run_guard": recipe.get("run_guard"),
                    "blocked_by": recipe.get("blocked_by") or activation_blockers,
                    "first_blocking_gate": recipe.get("first_blocking_gate"),
                    "blocked_by_goal_requirements": recipe.get("blocked_by_goal_requirements") or [],
                    "activation_status": recipe.get("activation_status"),
                    "activation_ready_trade_date": recipe.get("activation_ready_trade_date"),
                    "activation_ready_not_before_user_local": recipe.get(
                        "activation_ready_not_before_user_local"
                    ),
                    "next_unlock_command": recipe.get("next_unlock_command"),
                    "next_unlock_not_before_user_local": recipe.get("next_unlock_not_before_user_local"),
                    "replay_command_when_unlocked": recipe.get("replay_command_when_unlocked"),
                    "activation_unlock_plan": recipe.get("activation_unlock_plan") or activation_unlock_plan,
                    "compare_fields": recipe.get("compare_fields") or queue_item.get("compare_fields") or [],
                    "expected_evidence_artifacts": recipe.get("expected_evidence_artifacts") or [],
                    "recipe_index_within_drop_key": recipe_index,
                }
            )
    safe_to_start = bool(ordered_sweeps) and recipe_audit.get("safe_to_run_now") is True and not activation_blockers
    status = (
        "ready_to_materialize_configs_and_run_exact_opra_sweeps"
        if safe_to_start
        else "locked_until_activation_gates_pass"
    )
    return {
        "status": status,
        "safe_to_start_now": safe_to_start,
        "activation_blockers": activation_blockers,
        "activation_unlock_plan": activation_unlock_plan,
        "recipe_audit_status": recipe_audit.get("status"),
        "materialization_command": recipe_audit.get("materialization_command"),
        "materialization_dry_run_command": recipe_audit.get("materialization_dry_run_command"),
        "run_all_sweeps_command": "python scripts/run_ai_commodity_opra_progress.py --run-deferred-variant-sweeps",
        "run_all_sweeps_dry_run_command": (
            "python scripts/run_ai_commodity_opra_progress.py --run-deferred-variant-sweeps "
            "--deferred-variant-sweep-dry-run"
        ),
        "result_collection_command": "python scripts/run_ai_commodity_opra_progress.py --collect-deferred-variant-results",
        "ordered_sweep_count": len(ordered_sweeps),
        "ordered_sweeps": ordered_sweeps,
        "first_sweep_command": ordered_sweeps[0].get("run_command") if ordered_sweeps else None,
        "proof_fields_to_compare_after_each_sweep": [
            "verification_gate.replay_total_trades",
            "verification_gate.replay_profit_factor",
            "verification_gate.replay_total_return_pct",
            "verification_gate.gates.exact_replay_profit_factor_positive",
            "verification_gate.gates.exact_replay_total_return_positive",
            "scan.candidate_count",
            "scan.candidate_symbols",
        ],
        "promotion_evidence_required": _minimum_exact_variant_promotion_evidence(),
        "next_action": (
            "run_materialization_command_then_ordered_sweeps"
            if safe_to_start
            else "wait_for_exact_opra_activation_gates_then_rerun_materialization_dry_run"
        ),
    }


def build_post_fresh_scan_research_backlog(report: dict[str, Any]) -> dict[str, Any]:
    decision = (
        report.get("fresh_scan_iteration_decision")
        if isinstance(report.get("fresh_scan_iteration_decision"), dict)
        else {}
    )
    goal_audit = (
        report.get("goal_completion_audit")
        if isinstance(report.get("goal_completion_audit"), dict)
        else {}
    )
    exact_history = (
        report.get("exact_history_acquisition_plan")
        if isinstance(report.get("exact_history_acquisition_plan"), dict)
        else {}
    )
    verification = (
        report.get("verification_gate")
        if isinstance(report.get("verification_gate"), dict)
        else {}
    )
    gates = verification.get("gates") if isinstance(verification.get("gates"), dict) else {}
    readiness = report.get("readiness") if isinstance(report.get("readiness"), dict) else {}
    replay = report.get("replay") if isinstance(report.get("replay"), dict) else {}
    research_lab = (
        report.get("commodity_research_lab")
        if isinstance(report.get("commodity_research_lab"), dict)
        else {}
    )
    selected_outcome = (
        decision.get("selected_fresh_scan_outcome")
        if isinstance(decision.get("selected_fresh_scan_outcome"), dict)
        else {}
    )
    status = "waiting_for_fresh_scan_outcome"
    selected_condition = decision.get("selected_post_run_condition") or selected_outcome.get("condition")
    if decision.get("status") == "candidate_evidence_found":
        status = "defer_research_preserve_filters_and_accumulate_exact_history"
    elif decision.get("status") == "fresh_scan_zero_candidates_structural_review":
        status = "queued_until_exact_replay_unlock"
    elif decision.get("status") == "fresh_scan_data_freshness_still_blocked":
        status = "blocked_by_data_freshness"
    elif decision.get("status") == "waiting_for_fresh_opra_scan":
        status = "waiting_for_fresh_scan_outcome"
    top_drop_counts = [
        item for item in (decision.get("top_drop_counts") or []) if isinstance(item, dict) and item.get("drop_key")
    ]
    diagnostic_plan = [
        item
        for item in (decision.get("zero_candidate_diagnostic_plan") or [])
        if isinstance(item, dict) and item.get("drop_key")
    ]
    diagnostic_by_key = {str(item.get("drop_key")): item for item in diagnostic_plan}
    hypotheses: list[dict[str, Any]] = []
    for item in top_drop_counts[:5]:
        drop_key = str(item.get("drop_key"))
        base = _research_hypothesis_for_drop_key(drop_key)
        diagnostic = diagnostic_by_key.get(drop_key, {})
        hypotheses.append(
            {
                **base,
                "current_drop_count": item.get("count"),
                "example_symbols": diagnostic.get("example_symbols") or [],
                "representative_examples": diagnostic.get("representative_examples") or [],
                "production_filter_action": diagnostic.get("production_filter_action")
                or "preserve_filters_until_exact_replay_unlock",
                "allowed_now": False,
                "blocked_until": "exact_alpaca_opra_replay_ready_and_fresh_scan_evidence_recorded",
            }
        )
    remaining_exact_shared_quote_dates = exact_history.get("remaining_shared_quote_dates")
    exact_shared_ready = (
        gates.get("enough_exact_shared_quote_dates")
        if "enough_exact_shared_quote_dates" in gates
        else remaining_exact_shared_quote_dates == 0
    )
    readiness_ready = (
        gates.get("readiness_ready_for_exact_replay")
        if "readiness_ready_for_exact_replay" in gates
        else readiness.get("status") == "ready_for_exact_replay"
    )
    exact_replay_completed = (
        gates.get("exact_replay_completed")
        if "exact_replay_completed" in gates
        else bool(replay) and replay.get("error") in {None, ""}
    )
    exact_replay_has_trades = (
        gates.get("exact_replay_has_trades")
        if "exact_replay_has_trades" in gates
        else int(replay.get("total_trades") or 0) > 0
    )
    activation_gates = [
        {
            "name": "enough_exact_shared_quote_dates",
            "passed": exact_shared_ready is True,
            "actual": exact_history.get("current_shared_quote_dates"),
            "expected": exact_history.get("required_shared_quote_dates"),
        },
        {
            "name": "readiness_ready_for_exact_replay",
            "passed": readiness_ready is True,
            "actual": readiness.get("status"),
            "expected": "ready_for_exact_replay",
        },
        {
            "name": "exact_replay_completed",
            "passed": exact_replay_completed is True,
            "actual": replay.get("error"),
            "expected": None,
        },
        {
            "name": "exact_replay_has_trades",
            "passed": exact_replay_has_trades is True,
            "actual": replay.get("total_trades"),
            "expected": ">0",
        },
    ]
    activation_blockers = [item["name"] for item in activation_gates if item.get("passed") is not True]
    variant_unlock_runway = _deferred_variant_activation_unlock_plan(
        report,
        activation_gates=activation_gates,
        activation_blockers=activation_blockers,
    )
    unlock_status = (
        "ready_for_exact_replay_filter_tests"
        if not activation_blockers
        else "locked_until_exact_replay_can_measure_filter_changes"
    )
    deferred_test_queue = [
        {
            "rank": index + 1,
            "drop_key": hypothesis.get("drop_key"),
            "status": "ready_after_exact_replay" if not activation_blockers else "queued_locked",
            "exact_replay_test": hypothesis.get("exact_replay_test"),
            "research_action": hypothesis.get("research_action"),
            "example_symbols": hypothesis.get("example_symbols") or [],
            "representative_examples": hypothesis.get("representative_examples") or [],
            "variant_blueprint": (blueprint := _filter_variant_blueprint_for_drop_key(str(hypothesis.get("drop_key") or ""))),
            "variant_run_recipes": (
                variant_run_recipes := _deferred_variant_run_recipes(
                    drop_key=str(hypothesis.get("drop_key") or ""),
                    blueprint=blueprint,
                    activation_blockers=activation_blockers,
                    activation_unlock_plan=variant_unlock_runway,
                )
            ),
            "variant_run_recipe_count": len(variant_run_recipes),
            "first_blocking_gate": activation_blockers[0] if activation_blockers else None,
            "blocked_by_goal_requirements": list(
                dict.fromkeys(
                    requirement
                    for recipe in variant_run_recipes
                    for requirement in (recipe.get("blocked_by_goal_requirements") or [])
                )
            ),
            "activation_ready_trade_date": (
                variant_unlock_runway.get("history_depth_runway") or {}
            ).get("full_replay_unlock_trade_date")
            if isinstance(variant_unlock_runway.get("history_depth_runway"), dict)
            else None,
            "activation_ready_not_before_user_local": (
                variant_unlock_runway.get("history_depth_runway") or {}
            ).get("full_replay_unlock_not_before_user_local")
            if isinstance(variant_unlock_runway.get("history_depth_runway"), dict)
            else None,
            "next_unlock_command": variant_unlock_runway.get("next_capture_command"),
            "next_unlock_not_before_user_local": variant_unlock_runway.get("next_capture_not_before_user_local"),
            "compare_fields": [
                "verification_gate.replay_total_trades",
                "verification_gate.replay_profit_factor",
                "verification_gate.replay_total_return_pct",
                "scan.candidate_count",
                "scan.candidate_symbols",
            ],
            "guardrails": [
                "provider == alpaca:sip:opra",
                "proof_source_label == alpaca_opra_daily_snapshot",
                "use exact Alpaca OPRA replay metrics only",
                "do not promote bar-only research evidence",
                "keep production filters unchanged until a variant is measured",
            ],
            "blocked_by": activation_blockers,
            "activation_unlock_plan": variant_unlock_runway,
        }
        for index, hypothesis in enumerate(hypotheses)
    ]
    deferred_variant_run_recipe_count = sum(
        len(item.get("variant_run_recipes") or []) for item in deferred_test_queue
    )
    deferred_variant_recipe_audit = _deferred_variant_recipe_audit(
        deferred_test_queue=deferred_test_queue,
        activation_blockers=activation_blockers,
    )
    deferred_variant_execution_plan = _deferred_variant_execution_plan(
        deferred_test_queue=deferred_test_queue,
        recipe_audit=deferred_variant_recipe_audit,
        activation_blockers=activation_blockers,
        activation_unlock_plan=variant_unlock_runway,
    )
    return {
        "status": status,
        "selected_fresh_scan_condition": selected_condition,
        "production_filter_policy": "locked_until_exact_alpaca_opra_replay_is_ready",
        "safe_to_tune_filters_now": False,
        "unlock_status": unlock_status,
        "activation_gates": activation_gates,
        "activation_blockers": activation_blockers,
        "variant_unlock_runway": variant_unlock_runway,
        "exact_history_status": exact_history.get("status"),
        "remaining_exact_shared_quote_dates": remaining_exact_shared_quote_dates,
        "next_exact_capture_command": exact_history.get("next_capture_command"),
        "next_exact_capture_not_before_user_local": exact_history.get("next_capture_not_before_user_local"),
        "research_lab_status": research_lab.get("status"),
        "bar_only_positive_lanes": research_lab.get("positive_bar_only_lanes") or [],
        "bar_only_trade_count": research_lab.get("total_bar_fallback_trades"),
        "exact_bid_ask_trade_count": research_lab.get("total_exact_bid_ask_trades"),
        "bar_only_promotion_policy": "research_only_never_satisfies_exact_alpaca_opra_profitability_gate",
        "hypotheses": hypotheses,
        "deferred_test_queue": deferred_test_queue,
        "deferred_test_count": len(deferred_test_queue),
        "deferred_variant_run_recipe_count": deferred_variant_run_recipe_count,
        "deferred_variant_recipe_audit": deferred_variant_recipe_audit,
        "deferred_variant_execution_plan": deferred_variant_execution_plan,
        "next_action": (
            "run_fresh_opra_scan_at_not_before_time"
            if status == "waiting_for_fresh_scan_outcome"
            else selected_outcome.get("next_action")
            or decision.get("selected_post_run_next_action")
            or decision.get("next_action")
        ),
        "blocked_goal_requirements": goal_audit.get("failed_requirements"),
    }


def _resolve_report_path_under_root(root: Path, raw_path: Any) -> Path:
    root_path = Path(root).resolve()
    candidate = Path(str(raw_path or ""))
    if not candidate.is_absolute():
        candidate = root_path / candidate
    resolved = candidate.resolve()
    try:
        resolved.relative_to(root_path)
    except ValueError as exc:
        raise ValueError(f"Refusing to write outside workspace root: {resolved}") from exc
    return resolved


def _deferred_variant_recipes_from_backlog(backlog: dict[str, Any]) -> list[dict[str, Any]]:
    recipes: list[dict[str, Any]] = []
    for queue_item in list(backlog.get("deferred_test_queue") or []):
        if not isinstance(queue_item, dict):
            continue
        for recipe in list(queue_item.get("variant_run_recipes") or []):
            if isinstance(recipe, dict):
                recipes.append(recipe)
    return recipes


def materialize_deferred_variant_configs(
    report: dict[str, Any],
    *,
    root: Path = ROOT,
    dry_run: bool = False,
) -> dict[str, Any]:
    backlog = (
        report.get("post_fresh_scan_research_backlog")
        if isinstance(report.get("post_fresh_scan_research_backlog"), dict)
        else {}
    )
    audit = (
        backlog.get("deferred_variant_recipe_audit")
        if isinstance(backlog.get("deferred_variant_recipe_audit"), dict)
        else {}
    )
    activation_blockers = list(audit.get("activation_blockers") or backlog.get("activation_blockers") or [])
    recipes = _deferred_variant_recipes_from_backlog(backlog)
    preflight_checks = [
        {
            "name": "deferred_variant_recipe_audit_ready",
            "passed": audit.get("status") == "ready_with_verified_opra_recipe_contracts",
            "actual": audit.get("status"),
            "expected": "ready_with_verified_opra_recipe_contracts",
        },
        {
            "name": "deferred_variant_recipe_audit_safe_to_run_now",
            "passed": audit.get("safe_to_run_now") is True,
            "actual": audit.get("safe_to_run_now"),
            "expected": True,
        },
        {
            "name": "activation_blockers_empty",
            "passed": not activation_blockers,
            "actual": activation_blockers,
            "expected": [],
        },
        {
            "name": "recipe_contract_failures_empty",
            "passed": int(audit.get("failed_recipe_count") or 0) == 0,
            "actual": audit.get("failed_recipe_count"),
            "expected": 0,
        },
        {
            "name": "recipe_count_positive",
            "passed": len(recipes) > 0,
            "actual": len(recipes),
            "expected": ">0",
        },
    ]
    blocked = any(check.get("passed") is not True for check in preflight_checks)
    if blocked:
        return {
            "status": "blocked_by_activation_gates_or_recipe_audit",
            "dry_run": dry_run,
            "safe_to_materialize": False,
            "written_count": 0,
            "skipped_count": len(recipes),
            "preflight_checks": preflight_checks,
            "activation_blockers": activation_blockers,
            "recipe_audit_status": audit.get("status"),
            "next_action": "wait_for_activation_gates_then_rerun_materialization_command",
        }
    materialized: list[dict[str, Any]] = []
    for recipe in recipes:
        config = recipe.get("variant_config") if isinstance(recipe.get("variant_config"), dict) else {}
        target_path = _resolve_report_path_under_root(Path(root), recipe.get("variant_config_path"))
        materialized.append(
            {
                "variant_id": recipe.get("variant_id"),
                "variant_config_path": str(target_path),
                "status": "dry_run_ready_to_write" if dry_run else "written",
                "run_command": recipe.get("run_command"),
                "run_command_args": recipe.get("run_command_args"),
            }
        )
        if dry_run:
            continue
        target_path.parent.mkdir(parents=True, exist_ok=True)
        target_path.write_text(json.dumps(config, indent=2, sort_keys=True) + "\n", encoding="utf8")
    return {
        "status": "dry_run_ready_to_materialize" if dry_run else "materialized",
        "dry_run": dry_run,
        "safe_to_materialize": True,
        "written_count": 0 if dry_run else len(materialized),
        "skipped_count": 0,
        "preflight_checks": preflight_checks,
        "activation_blockers": [],
        "recipe_audit_status": audit.get("status"),
        "materialized_configs": materialized,
        "next_action": "run_exact_opra_variant_sweeps" if not dry_run else "rerun_without_dry_run_after_review",
    }


def _tail_text(value: Any, *, limit: int = 4000) -> str:
    text = str(value or "")
    return text[-limit:] if len(text) > limit else text


def run_deferred_variant_sweeps(
    report: dict[str, Any],
    *,
    root: Path = ROOT,
    dry_run: bool = False,
    max_sweeps: int | None = None,
) -> dict[str, Any]:
    backlog = (
        report.get("post_fresh_scan_research_backlog")
        if isinstance(report.get("post_fresh_scan_research_backlog"), dict)
        else {}
    )
    execution_plan = (
        backlog.get("deferred_variant_execution_plan")
        if isinstance(backlog.get("deferred_variant_execution_plan"), dict)
        else {}
    )
    sweeps = [item for item in list(execution_plan.get("ordered_sweeps") or []) if isinstance(item, dict)]
    if max_sweeps is not None:
        sweeps = sweeps[: max(int(max_sweeps), 0)]
    materialization = materialize_deferred_variant_configs(
        report,
        root=root,
        dry_run=dry_run,
    )
    safe_to_run = (
        materialization.get("safe_to_materialize") is True
        and execution_plan.get("safe_to_start_now") is True
        and bool(sweeps)
    )
    planned_sweeps: list[dict[str, Any]] = []
    for sweep in sweeps:
        command_args = [str(part) for part in list(sweep.get("run_command_args") or [])]
        planned_sweeps.append(
            {
                "sequence": sweep.get("sequence"),
                "drop_key": sweep.get("drop_key"),
                "variant_id": sweep.get("variant_id"),
                "run_slug": sweep.get("run_slug"),
                "variant_config_path": sweep.get("variant_config_path"),
                "run_command": sweep.get("run_command"),
                "run_command_args": command_args,
                "command_present": bool(command_args),
            }
        )
    if not safe_to_run:
        return {
            "status": "blocked_by_activation_gates_or_recipe_audit",
            "dry_run": dry_run,
            "safe_to_run": False,
            "materialization": materialization,
            "planned_sweep_count": len(planned_sweeps),
            "executed_count": 0,
            "skipped_count": len(planned_sweeps),
            "activation_blockers": execution_plan.get("activation_blockers") or materialization.get("activation_blockers") or [],
            "recipe_audit_status": execution_plan.get("recipe_audit_status") or materialization.get("recipe_audit_status"),
            "next_action": "wait_for_activation_gates_then_rerun_deferred_variant_sweep_dry_run",
        }
    command_failures = [item for item in planned_sweeps if not item.get("command_present")]
    if command_failures:
        return {
            "status": "blocked_by_missing_sweep_commands",
            "dry_run": dry_run,
            "safe_to_run": False,
            "materialization": materialization,
            "planned_sweeps": planned_sweeps,
            "planned_sweep_count": len(planned_sweeps),
            "executed_count": 0,
            "skipped_count": len(planned_sweeps),
            "command_failures": command_failures,
            "next_action": "repair_deferred_variant_run_recipe_commands",
        }
    if dry_run:
        return {
            "status": "dry_run_ready_to_run_exact_opra_sweeps",
            "dry_run": True,
            "safe_to_run": True,
            "materialization": materialization,
            "planned_sweeps": planned_sweeps,
            "planned_sweep_count": len(planned_sweeps),
            "executed_count": 0,
            "skipped_count": len(planned_sweeps),
            "next_action": "rerun_without_dry_run_to_execute_ordered_exact_opra_sweeps",
        }
    run_results: list[dict[str, Any]] = []
    for sweep in planned_sweeps:
        command_args = [str(part) for part in list(sweep.get("run_command_args") or [])]
        started_at = _utc_iso(_utc_now())
        completed = subprocess.run(
            command_args,
            cwd=Path(root),
            text=True,
            capture_output=True,
        )
        run_results.append(
            {
                "sequence": sweep.get("sequence"),
                "drop_key": sweep.get("drop_key"),
                "variant_id": sweep.get("variant_id"),
                "run_slug": sweep.get("run_slug"),
                "run_command": sweep.get("run_command"),
                "started_at_utc": started_at,
                "completed_at_utc": _utc_iso(_utc_now()),
                "returncode": completed.returncode,
                "stdout_tail": _tail_text(completed.stdout),
                "stderr_tail": _tail_text(completed.stderr),
            }
        )
        if completed.returncode != 0:
            break
    failed = [item for item in run_results if int(item.get("returncode") or 0) != 0]
    collection = collect_deferred_variant_results(report, root=root)
    return {
        "status": "variant_sweep_failed" if failed else "completed",
        "dry_run": False,
        "safe_to_run": True,
        "materialization": materialization,
        "planned_sweeps": planned_sweeps,
        "planned_sweep_count": len(planned_sweeps),
        "executed_count": len(run_results),
        "skipped_count": max(len(planned_sweeps) - len(run_results), 0),
        "failed_count": len(failed),
        "run_results": run_results,
        "result_collection": collection,
        "next_action": (
            "inspect_failed_variant_sweep"
            if failed
            else "collect_deferred_variant_results_and_review_promotable_candidates"
        ),
    }


def _read_json_if_exists(path: Path) -> dict[str, Any] | None:
    if not path.exists() or not path.is_file():
        return None
    try:
        payload = json.loads(path.read_text(encoding="utf8"))
    except (json.JSONDecodeError, OSError):
        return None
    return payload if isinstance(payload, dict) else None


def _latest_research_run_for_slug(root: Path, slug: str) -> Path | None:
    if not slug:
        return None
    run_root = Path(root) / "research_runs"
    if not run_root.exists():
        return None
    matches = sorted(
        [path for path in run_root.glob(f"*_{slug}") if path.is_dir()],
        key=lambda path: path.name,
    )
    return matches[-1] if matches else None


def _research_runs_for_slug(root: Path, slug: str) -> list[Path]:
    if not slug:
        return []
    run_root = Path(root) / "research_runs"
    if not run_root.exists():
        return []
    return sorted(
        [path for path in run_root.glob(f"*_{slug}") if path.is_dir()],
        key=lambda path: path.name,
    )


def _float_or_none(value: Any) -> float | None:
    if value is None:
        return None
    try:
        parsed = float(value)
    except (TypeError, ValueError):
        return None
    return parsed if math.isfinite(parsed) else None


def _int_or_zero(value: Any) -> int:
    try:
        return int(value or 0)
    except (TypeError, ValueError):
        return 0


def _variant_live_scan_evidence(primary_report: dict[str, Any] | None, result: dict[str, Any]) -> dict[str, Any]:
    candidates: list[dict[str, Any]] = []
    if isinstance(primary_report, dict):
        for key in ("variant_live_scan", "live_scan", "scan"):
            value = primary_report.get(key)
            if isinstance(value, dict):
                candidates.append(value)
    for key in ("variant_live_scan", "live_scan", "scan"):
        value = result.get(key)
        if isinstance(value, dict):
            candidates.append(value)
    for candidate in candidates:
        candidate_count = _int_or_zero(
            candidate.get("candidate_count")
            if candidate.get("candidate_count") is not None
            else candidate.get("live_scan_candidate_count")
        )
        inside_exact_proof = (
            candidate.get("live_scan_candidate_inside_exact_proof_universe")
            if "live_scan_candidate_inside_exact_proof_universe" in candidate
            else candidate.get("live_scan_candidates_all_inside_exact_proof")
        )
        if inside_exact_proof is None:
            inside_exact_proof = candidate.get("candidate_inside_exact_proof_universe")
        if candidate_count > 0 and inside_exact_proof is True:
            return {
                "passed": True,
                "candidate_count": candidate_count,
                "candidate_symbols": candidate.get("candidate_symbols") or candidate.get("live_scan_candidate_symbols") or [],
                "live_scan_candidate_inside_exact_proof_universe": True,
            }
    return {
        "passed": False,
        "candidate_count": 0,
        "candidate_symbols": [],
        "live_scan_candidate_inside_exact_proof_universe": False,
    }


def _variant_result_evidence_fingerprint(
    primary_report: dict[str, Any] | None,
    result: dict[str, Any],
    live_scan_evidence: dict[str, Any],
) -> str:
    if not isinstance(primary_report, dict) or not isinstance(result, dict) or not result:
        return ""
    volatile_keys = {
        "run_at",
        "generated_at",
        "timestamp",
        "started_at",
        "completed_at",
        "created_at",
        "updated_at",
        "elapsed_seconds",
        "duration_seconds",
        "run_id",
        "run_slug",
        "run_dir",
        "run_path",
        "variant_id",
        "variant_config_path",
        "output_dir",
        "artifact_path",
        "manifest_path",
        "command",
        "stdout",
        "stderr",
    }

    def _is_volatile_key(key: Any) -> bool:
        normalized = str(key).strip().lower()
        return normalized in volatile_keys or normalized.endswith("_utc")

    def _canonical(value: Any) -> Any:
        if isinstance(value, dict):
            return {
                str(key): _canonical(item)
                for key, item in value.items()
                if not _is_volatile_key(key)
            }
        if isinstance(value, list):
            return [_canonical(item) for item in value]
        return value

    evidence = {
        "result": _canonical(result),
        "live_scan_evidence": _canonical(live_scan_evidence),
        "variant_live_scan": _canonical(primary_report.get("variant_live_scan")),
        "live_scan": _canonical(primary_report.get("live_scan")),
        "scan": _canonical(primary_report.get("scan")),
    }
    return json.dumps(evidence, sort_keys=True, default=str, separators=(",", ":"))


def _baseline_exact_opra_context(report: dict[str, Any]) -> dict[str, Any]:
    verification = (
        report.get("verification_gate")
        if isinstance(report.get("verification_gate"), dict)
        else {}
    )
    verification_gates = verification.get("gates") if isinstance(verification.get("gates"), dict) else {}
    profit_factor = _float_or_none(verification.get("replay_profit_factor"))
    total_return_pct = _float_or_none(verification.get("replay_total_return_pct"))
    total_trades = _int_or_zero(verification.get("replay_total_trades"))
    exact_ready = (
        verification_gates.get("alpaca_sip_opra_provider") is True
        and verification_gates.get("alpaca_opra_source_filtered") is True
        and verification_gates.get("exact_replay_completed") is True
        and verification_gates.get("exact_replay_has_trades") is True
        and profit_factor is not None
        and total_return_pct is not None
        and total_trades > 0
    )
    return {
        "profit_factor": profit_factor,
        "total_return_pct": total_return_pct,
        "total_trades": total_trades,
        "exact_ready": exact_ready,
        "source_policy_ready": (
            verification_gates.get("alpaca_sip_opra_provider") is True
            and verification_gates.get("alpaca_opra_source_filtered") is True
        ),
    }


def collect_deferred_variant_results(
    report: dict[str, Any],
    *,
    root: Path = ROOT,
) -> dict[str, Any]:
    backlog = (
        report.get("post_fresh_scan_research_backlog")
        if isinstance(report.get("post_fresh_scan_research_backlog"), dict)
        else {}
    )
    execution_plan = (
        backlog.get("deferred_variant_execution_plan")
        if isinstance(backlog.get("deferred_variant_execution_plan"), dict)
        else {}
    )
    baseline_context = _baseline_exact_opra_context(report)
    baseline_profit_factor = _float_or_none(baseline_context.get("profit_factor"))
    baseline_total_return_pct = _float_or_none(baseline_context.get("total_return_pct"))
    baseline_exact_ready = baseline_context.get("exact_ready") is True
    sweeps = [item for item in list(execution_plan.get("ordered_sweeps") or []) if isinstance(item, dict)]
    result_items: list[dict[str, Any]] = []
    seen_run_slugs: set[str] = set()
    seen_run_dirs: set[str] = set()
    seen_evidence_fingerprints: set[str] = set()
    for sweep in sweeps:
        run_slug = str(sweep.get("run_slug") or "").strip()
        run_dirs = _research_runs_for_slug(Path(root), run_slug)
        run_dir = run_dirs[-1] if run_dirs else None
        duplicate_run_slug = bool(run_slug and run_slug in seen_run_slugs)
        if run_slug:
            seen_run_slugs.add(run_slug)
        run_dir_key = str(run_dir.resolve()) if run_dir is not None else ""
        duplicate_run_dir = bool(run_dir_key and run_dir_key in seen_run_dirs) or len(run_dirs) > 1
        if run_dir_key:
            seen_run_dirs.add(run_dir_key)
        manifest = _read_json_if_exists(run_dir / "manifest.json") if run_dir is not None else None
        variant_config = _read_json_if_exists(run_dir / "variant_config.json") if run_dir is not None else None
        primary_report = _read_json_if_exists(run_dir / "primary_report.json") if run_dir is not None else None
        result = (
            primary_report.get("result")
            if isinstance(primary_report, dict) and isinstance(primary_report.get("result"), dict)
            else {}
        )
        total_trades = _int_or_zero(result.get("total_trades"))
        profit_factor = _float_or_none(result.get("profit_factor"))
        total_return_pct = _float_or_none(
            result.get("total_return_pct")
            if result.get("total_return_pct") is not None
            else result.get("avg_pnl_pct")
        )
        quote_coverage = _float_or_none(
            manifest.get("require_quote_coverage") if isinstance(manifest, dict) else None
        )
        live_scan_evidence = _variant_live_scan_evidence(primary_report, result)
        evidence_fingerprint = _variant_result_evidence_fingerprint(primary_report, result, live_scan_evidence)
        duplicate_evidence_fingerprint = bool(
            evidence_fingerprint and evidence_fingerprint in seen_evidence_fingerprints
        )
        if evidence_fingerprint:
            seen_evidence_fingerprints.add(evidence_fingerprint)
        checks = [
            {
                "name": "research_run_found",
                "passed": run_dir is not None,
                "actual": str(run_dir) if run_dir is not None else None,
                "expected": f"research_runs/*_{run_slug}",
            },
            {
                "name": "unique_run_slug",
                "passed": bool(run_slug) and not duplicate_run_slug,
                "actual": run_slug,
                "expected": "non-empty unique run_slug per deferred sweep",
            },
            {
                "name": "unique_research_run_dir",
                "passed": run_dir is None or not duplicate_run_dir,
                "actual": [str(path) for path in run_dirs] if run_dirs else None,
                "expected": "each deferred sweep maps to a distinct research run directory",
            },
            {
                "name": "unique_variant_evidence",
                "passed": not evidence_fingerprint or not duplicate_evidence_fingerprint,
                "actual": "duplicate" if duplicate_evidence_fingerprint else "unique",
                "expected": "each deferred sweep produces distinct replay and live-scan evidence",
            },
            {
                "name": "manifest_completed",
                "passed": isinstance(manifest, dict) and manifest.get("status") == "completed",
                "actual": manifest.get("status") if isinstance(manifest, dict) else None,
                "expected": "completed",
            },
            {
                "name": "variant_config_provider_is_alpaca_sip_opra",
                "passed": isinstance(variant_config, dict) and variant_config.get("provider") == "alpaca:sip:opra",
                "actual": variant_config.get("provider") if isinstance(variant_config, dict) else None,
                "expected": "alpaca:sip:opra",
            },
            {
                "name": "variant_config_proof_source_is_alpaca_opra_daily_snapshot",
                "passed": isinstance(variant_config, dict)
                and variant_config.get("proof_source_label") == ALPACA_OPRA_SOURCE_LABEL,
                "actual": variant_config.get("proof_source_label") if isinstance(variant_config, dict) else None,
                "expected": ALPACA_OPRA_SOURCE_LABEL,
            },
            {
                "name": "truth_lane_is_historical_imported_daily",
                "passed": isinstance(manifest, dict) and manifest.get("truth_lane") == DEFERRED_VARIANT_TRUTH_LANE,
                "actual": manifest.get("truth_lane") if isinstance(manifest, dict) else None,
                "expected": DEFERRED_VARIANT_TRUTH_LANE,
            },
            {
                "name": "quote_coverage_requirement_preserved",
                "passed": quote_coverage is not None and quote_coverage >= float(DEFERRED_VARIANT_REQUIRED_QUOTE_COVERAGE),
                "actual": quote_coverage,
                "expected": f">={DEFERRED_VARIANT_REQUIRED_QUOTE_COVERAGE}",
            },
            {
                "name": "commodity_playbook_used",
                "passed": isinstance(manifest, dict)
                and DEFERRED_VARIANT_PLAYBOOK in set(manifest.get("playbooks") or []),
                "actual": manifest.get("playbooks") if isinstance(manifest, dict) else None,
                "expected": DEFERRED_VARIANT_PLAYBOOK,
            },
            {
                "name": "primary_report_present",
                "passed": isinstance(primary_report, dict) and isinstance(result, dict),
                "actual": primary_report is not None,
                "expected": True,
            },
            {
                "name": "variant_replay_total_trades_above_zero",
                "passed": total_trades > 0,
                "actual": total_trades,
                "expected": ">0",
            },
            {
                "name": "variant_replay_profit_factor_positive",
                "passed": profit_factor is not None and profit_factor > 1.0,
                "actual": profit_factor,
                "expected": ">1.0",
            },
            {
                "name": "variant_replay_total_return_pct_positive",
                "passed": total_return_pct is not None and total_return_pct > 0.0,
                "actual": total_return_pct,
                "expected": ">0.0",
            },
            {
                "name": "baseline_exact_alpaca_opra_replay_recorded_before_variant",
                "passed": baseline_exact_ready,
                "actual": baseline_context,
                "expected": "current_verification_gate_exact_opra_replay_with_trades_and_metrics",
            },
            {
                "name": "variant_replay_profit_factor_improves_vs_baseline_and_exceeds_1",
                "passed": (
                    profit_factor is not None
                    and baseline_profit_factor is not None
                    and profit_factor > 1.0
                    and profit_factor > baseline_profit_factor
                ),
                "actual": {"variant": profit_factor, "baseline": baseline_profit_factor},
                "expected": "variant > baseline and >1.0",
            },
            {
                "name": "variant_replay_total_return_pct_improves_vs_baseline_and_exceeds_0",
                "passed": (
                    total_return_pct is not None
                    and baseline_total_return_pct is not None
                    and total_return_pct > 0.0
                    and total_return_pct > baseline_total_return_pct
                ),
                "actual": {"variant": total_return_pct, "baseline": baseline_total_return_pct},
                "expected": "variant > baseline and >0.0",
            },
            {
                "name": "live_scan_candidate_inside_exact_proof_universe_after_variant",
                "passed": live_scan_evidence.get("passed") is True,
                "actual": live_scan_evidence,
                "expected": "post_variant_live_scan_candidate_count_above_zero_inside_exact_proof_universe",
            },
        ]
        promotable = all(check.get("passed") is True for check in checks)
        result_items.append(
            {
                "sequence": sweep.get("sequence"),
                "drop_key": sweep.get("drop_key"),
                "variant_id": sweep.get("variant_id"),
                "run_slug": run_slug,
                "run_dir": str(run_dir) if run_dir is not None else None,
                "status": "promotable_candidate" if promotable else "not_promotable",
                "promotable": promotable,
                "total_trades": total_trades,
                "profit_factor": profit_factor,
                "total_return_pct": total_return_pct,
                "baseline": baseline_context,
                "live_scan_evidence": live_scan_evidence,
                "evidence_fingerprint": evidence_fingerprint,
                "checks": checks,
                "failed_checks": [check["name"] for check in checks if check.get("passed") is not True],
            }
        )
    ranked = sorted(
        result_items,
        key=lambda item: (
            bool(item.get("promotable")),
            float(item.get("profit_factor") or 0.0),
            float(item.get("total_return_pct") or 0.0),
            int(item.get("total_trades") or 0),
        ),
        reverse=True,
    )
    result_count = sum(
        1
        for item in result_items
        if item.get("run_dir")
        and "unique_run_slug" not in item.get("failed_checks", [])
        and "unique_research_run_dir" not in item.get("failed_checks", [])
        and "unique_variant_evidence" not in item.get("failed_checks", [])
    )
    duplicate_result_count = sum(
        1
        for item in result_items
        if "unique_run_slug" in item.get("failed_checks", [])
        or "unique_research_run_dir" in item.get("failed_checks", [])
        or "unique_variant_evidence" in item.get("failed_checks", [])
    )
    promotable_count = sum(1 for item in result_items if item.get("promotable") is True)
    has_duplicate_evidence = duplicate_result_count > 0
    if not sweeps:
        status = "no_deferred_variant_sweeps_defined"
    elif has_duplicate_evidence:
        status = "variant_results_collected_with_duplicate_evidence"
    elif result_count == 0:
        status = "no_variant_results_collected"
    elif promotable_count:
        status = "promotable_variant_candidates_found"
    else:
        status = "variant_results_collected_no_promotable_candidate"
    return {
        "status": status,
        "result_count": result_count,
        "missing_result_count": max(len(sweeps) - result_count, 0),
        "duplicate_result_count": duplicate_result_count,
        "promotable_count": promotable_count,
        "best_candidate": (
            ranked[0]
            if ranked and ranked[0].get("promotable") and not has_duplicate_evidence
            else None
        ),
        "ranked_results": ranked,
        "proof_source_policy": "alpaca_sip_opra_variant_config_and_historical_imported_daily_manifest_required",
        "next_action": (
            "review_best_candidate_against_goal_completion_audit"
            if promotable_count and not has_duplicate_evidence
            else "run_ordered_exact_opra_variant_sweeps_after_activation"
        ),
    }


def build_deferred_variant_promotion_review(
    report: dict[str, Any],
    *,
    root: Path = ROOT,
) -> dict[str, Any]:
    backlog = (
        report.get("post_fresh_scan_research_backlog")
        if isinstance(report.get("post_fresh_scan_research_backlog"), dict)
        else {}
    )
    execution_plan = (
        backlog.get("deferred_variant_execution_plan")
        if isinstance(backlog.get("deferred_variant_execution_plan"), dict)
        else {}
    )
    collection = (
        backlog.get("deferred_variant_result_collection")
        if isinstance(backlog.get("deferred_variant_result_collection"), dict)
        else collect_deferred_variant_results(report, root=root)
    )
    baseline_context = _baseline_exact_opra_context(report)
    activation_blockers = list(execution_plan.get("activation_blockers") or backlog.get("activation_blockers") or [])
    best_candidate = (
        collection.get("best_candidate")
        if isinstance(collection.get("best_candidate"), dict)
        else None
    )
    promotable_count = _int_or_zero(collection.get("promotable_count"))
    result_count = _int_or_zero(collection.get("result_count"))
    duplicate_result_count = _int_or_zero(collection.get("duplicate_result_count"))
    failed_checks = list(best_candidate.get("failed_checks") or []) if best_candidate else []
    checks = [
        {
            "name": "activation_gates_passed_before_promotion",
            "passed": not activation_blockers,
            "actual": activation_blockers,
            "expected": [],
        },
        {
            "name": "baseline_exact_alpaca_opra_replay_recorded_before_variant",
            "passed": baseline_context.get("exact_ready") is True,
            "actual": baseline_context,
            "expected": "current_exact_opra_baseline_replay_with_trades_and_metrics",
        },
        {
            "name": "completed_variant_results_collected",
            "passed": result_count > 0,
            "actual": result_count,
            "expected": ">0",
        },
        {
            "name": "promotable_variant_candidate_present",
            "passed": promotable_count > 0 and best_candidate is not None,
            "actual": promotable_count,
            "expected": ">0",
        },
        {
            "name": "deferred_variant_results_are_unique",
            "passed": duplicate_result_count == 0,
            "actual": duplicate_result_count,
            "expected": 0,
        },
        {
            "name": "best_candidate_all_exact_opra_checks_pass",
            "passed": best_candidate is not None and not failed_checks,
            "actual": failed_checks,
            "expected": [],
        },
    ]
    blockers = [check["name"] for check in checks if check.get("passed") is not True]
    promotion_allowed = not blockers
    if promotion_allowed:
        next_action = "review_best_candidate_for_control_rollout_after_exact_opra_evidence_snapshot"
    elif activation_blockers:
        next_action = "wait_for_activation_gates_then_run_deferred_variant_sweeps"
    elif result_count == 0:
        next_action = "run_deferred_variant_sweeps_then_collect_results"
    elif promotable_count == 0:
        next_action = "keep_production_filters_locked_and_design_next_exact_opra_variant_batch"
    else:
        next_action = "repair_failed_promotion_evidence_before_any_rollout"
    return {
        "status": "promotion_allowed" if promotion_allowed else "promotion_blocked",
        "promotion_allowed": promotion_allowed,
        "best_candidate": best_candidate,
        "baseline": baseline_context,
        "collection_status": collection.get("status"),
        "result_count": result_count,
        "missing_result_count": collection.get("missing_result_count"),
        "promotable_count": promotable_count,
        "activation_blockers": activation_blockers,
        "checks": checks,
        "blockers": blockers,
        "evidence_required": _minimum_exact_variant_promotion_evidence(),
        "production_filter_policy": "do_not_change_production_filters_until_promotion_allowed_true",
        "next_action": next_action,
    }


def build_exact_profitability_blocker_review(report: dict[str, Any]) -> dict[str, Any]:
    verification = (
        report.get("verification_gate")
        if isinstance(report.get("verification_gate"), dict)
        else {}
    )
    gates = verification.get("gates") if isinstance(verification.get("gates"), dict) else {}
    exact_history = (
        report.get("exact_history_acquisition_plan")
        if isinstance(report.get("exact_history_acquisition_plan"), dict)
        else {}
    )
    exact_history_backfill_audit = (
        report.get("exact_history_backfill_capability_audit")
        if isinstance(report.get("exact_history_backfill_capability_audit"), dict)
        else exact_history.get("backfill_capability_audit")
        if isinstance(exact_history.get("backfill_capability_audit"), dict)
        else {}
    )
    if not exact_history_backfill_audit:
        exact_history_backfill_audit = build_exact_history_backfill_capability_audit(report)
    backlog = (
        report.get("post_fresh_scan_research_backlog")
        if isinstance(report.get("post_fresh_scan_research_backlog"), dict)
        else {}
    )
    promotion_review = (
        backlog.get("deferred_variant_promotion_review")
        if isinstance(backlog.get("deferred_variant_promotion_review"), dict)
        else {}
    )
    goal_evidence_plan = (
        report.get("goal_completion_evidence_plan")
        if isinstance(report.get("goal_completion_evidence_plan"), dict)
        else {}
    )
    if not goal_evidence_plan:
        goal_evidence_plan = build_goal_completion_evidence_plan(report)
    goal_evidence_requirements = {
        str(item.get("requirement")): item
        for item in goal_evidence_plan.get("requirements") or []
        if isinstance(item, dict) and item.get("requirement")
    }
    live_candidate_evidence = goal_evidence_requirements.get("live_scan_has_verifiable_candidate", {})
    first_auxiliary_evidence = (
        goal_evidence_plan.get("first_auxiliary_evidence_opportunity")
        if isinstance(goal_evidence_plan.get("first_auxiliary_evidence_opportunity"), dict)
        else {}
    )
    proof_source_isolation = _proof_source_isolation_contract(report)
    proof_source_isolation_clean = (
        proof_source_isolation.get("status") == "isolated_to_alpaca_opra_proof_source"
        and not proof_source_isolation.get("blockers")
    )
    history_depth_runway = _exact_profitability_history_depth_runway(report)
    check_specs = [
        ("uses_alpaca_sip_opra_live_source", gates.get("alpaca_sip_opra_provider") is True, gates.get("alpaca_sip_opra_provider")),
        ("uses_alpaca_opra_daily_snapshot_proof_source", gates.get("alpaca_opra_source_filtered") is True, gates.get("alpaca_opra_source_filtered")),
        (
            GOAL_REQUIREMENT_EXACT_PROOF_SOURCE_ISOLATION,
            proof_source_isolation_clean,
            _proof_source_goal_current_evidence(proof_source_isolation),
        ),
        ("has_required_exact_alpaca_opra_history_depth", gates.get("enough_exact_shared_quote_dates") is True, gates.get("enough_exact_shared_quote_dates")),
        ("readiness_ready_for_exact_replay", gates.get("readiness_ready_for_exact_replay") is True, gates.get("readiness_ready_for_exact_replay")),
        ("exact_replay_completed", gates.get("exact_replay_completed") is True, gates.get("exact_replay_completed")),
        ("exact_replay_has_trades", gates.get("exact_replay_has_trades") is True, gates.get("exact_replay_has_trades")),
        ("exact_replay_profit_factor_positive", gates.get("exact_replay_profit_factor_positive") is True, gates.get("exact_replay_profit_factor_positive")),
        ("exact_replay_total_return_positive", gates.get("exact_replay_total_return_positive") is True, gates.get("exact_replay_total_return_positive")),
        ("live_scan_has_candidate", gates.get("live_scan_has_candidate") is True, gates.get("live_scan_has_candidate")),
        (
            "live_scan_candidate_inside_exact_proof_universe",
            gates.get("live_scan_candidate_inside_exact_proof_universe") is True,
            gates.get("live_scan_candidate_inside_exact_proof_universe"),
        ),
    ]
    checks = [
        {
            "name": name,
            "passed": passed,
            "actual": actual,
            "expected": True,
        }
        for name, passed, actual in check_specs
    ]
    blockers = [check["name"] for check in checks if check.get("passed") is not True]
    source_contract_blockers = [
        name
        for name in (
            "uses_alpaca_sip_opra_live_source",
            "uses_alpaca_opra_daily_snapshot_proof_source",
            GOAL_REQUIREMENT_EXACT_PROOF_SOURCE_ISOLATION,
        )
        if name in blockers
    ]
    history_blockers = [
        name
        for name in ("has_required_exact_alpaca_opra_history_depth", "readiness_ready_for_exact_replay")
        if name in blockers
    ]
    replay_blockers = [
        name
        for name in (
            "exact_replay_completed",
            "exact_replay_has_trades",
            "exact_replay_profit_factor_positive",
            "exact_replay_total_return_positive",
        )
        if name in blockers
    ]
    live_candidate_blockers = [
        name
        for name in ("live_scan_has_candidate", "live_scan_candidate_inside_exact_proof_universe")
        if name in blockers
    ]
    exact_replay_ready = (
        gates.get("enough_exact_shared_quote_dates") is True
        and gates.get("readiness_ready_for_exact_replay") is True
        and gates.get("exact_replay_completed") is True
        and gates.get("exact_replay_has_trades") is True
    )
    exact_replay_profitable = (
        gates.get("exact_replay_profit_factor_positive") is True
        and gates.get("exact_replay_total_return_positive") is True
    )
    live_candidate_ready = (
        gates.get("live_scan_has_candidate") is True
        and gates.get("live_scan_candidate_inside_exact_proof_universe") is True
    )
    source_contract_command = "python scripts/run_ai_commodity_opra_progress.py --refresh-derived-from-latest --json"
    history_depth_command = (
        exact_history.get("local_exact_store_refresh_command")
        if exact_history_backfill_audit.get("local_exact_store_refresh_can_advance_history_depth") is True
        else exact_history.get("next_capture_command")
        or history_depth_runway.get("next_capture_command")
        or POST_CAPTURE_READBACK_COMMAND
    )
    history_depth_not_before = (
        exact_history.get("next_capture_not_before_user_local")
        or history_depth_runway.get("next_capture_not_before_user_local")
    )
    exact_replay_command = POST_CAPTURE_EXACT_REPLAY_COMMAND
    variant_measurement_command = (
        "python scripts/run_ai_commodity_opra_progress.py --run-deferred-variant-sweeps"
        if promotion_review.get("promotion_allowed") is not True
        else "python scripts/run_ai_commodity_opra_progress.py --collect-deferred-variant-results"
    )
    live_candidate_command = "python scripts/run_ai_commodity_opra_progress.py --skip-capture"
    live_candidate_next_action = (
        live_candidate_evidence.get("next_action")
        or first_auxiliary_evidence.get("next_action")
        or "run_fresh_opra_scan_or_review_zero_candidate_diagnostics"
    )
    live_candidate_next_command = (
        live_candidate_evidence.get("evidence_command")
        or first_auxiliary_evidence.get("command")
        or live_candidate_command
    )
    live_candidate_next_command_role = (
        live_candidate_evidence.get("evidence_command_role")
        or first_auxiliary_evidence.get("command_role")
        or "fresh_live_candidate_scan_evidence"
    )
    live_candidate_not_before = (
        live_candidate_evidence.get("not_before_user_local")
        or first_auxiliary_evidence.get("not_before_user_local")
    )
    live_candidate_window_end = (
        live_candidate_evidence.get("window_end_user_local")
        or first_auxiliary_evidence.get("window_end_user_local")
    )
    live_candidate_evidence_fields = _unique_strings(
        [
            "verification_gate.live_scan_candidate_count",
            "verification_gate.live_scan_candidate_symbols",
            "scan.candidate_count",
            "scan.candidate_symbols",
            "scan.quote_freshness_context.status",
            "scan.scan_drop_reason_audit_status",
            "scan.scan_drop_reason_count",
            "goal_completion_evidence_plan.first_auxiliary_evidence_opportunity",
            "scan_proof_universe_alignment.live_scan_candidates_all_inside_exact_proof",
        ]
    )
    live_candidate_material_progress = _unique_strings(
        [
            "verification_gate.live_scan_candidate_count > 0",
            "verification_gate.live_scan_candidate_symbols nonempty",
            "scan_proof_universe_alignment.live_scan_candidates_all_inside_exact_proof true",
            live_candidate_evidence.get("material_progress_if"),
            first_auxiliary_evidence.get("material_progress_if"),
        ]
    )
    completion_contract_command = POST_CAPTURE_READBACK_COMMAND
    history_depth_next_action = (
        "refresh_derived_history_from_local_alpaca_opra_store"
        if exact_history_backfill_audit.get("local_exact_store_refresh_can_advance_history_depth") is True
        else exact_history.get("next_action")
        or "continue_forward_daily_alpaca_opra_snapshot_capture"
    )
    history_depth_command_role = (
        "refresh_local_exact_alpaca_opra_store_evidence"
        if exact_history_backfill_audit.get("local_exact_store_refresh_can_advance_history_depth") is True
        else "guarded_forward_alpaca_opra_capture"
    )
    if not blockers:
        status = "verified_profitability_ready_for_goal_completion_audit"
        primary_path_status = "complete_current_baseline_exact_opra_profitable"
        current_primary_blocker = None
        next_action = "review_goal_completion_audit_for_completion"
        next_command = completion_contract_command
    elif source_contract_blockers:
        status = "blocked_by_source_or_completion_contract"
        primary_path_status = "source_or_proof_contract_blocked"
        current_primary_blocker = source_contract_blockers[0]
        next_action = proof_source_isolation.get("next_action") or "repair_source_or_completion_contract_before_goal_update"
        next_command = source_contract_command
    elif not exact_replay_ready:
        status = "blocked_waiting_for_exact_opra_history_or_replay"
        primary_path_status = "waiting_for_exact_opra_history_or_replay"
        current_primary_blocker = history_blockers[0] if history_blockers else replay_blockers[0]
        next_action = history_depth_next_action if history_blockers else "run_exact_replay_after_required_history_depth"
        next_command = history_depth_command if history_blockers else exact_replay_command
    elif not exact_replay_profitable:
        status = "blocked_exact_replay_not_profitable"
        primary_path_status = "baseline_exact_replay_not_profitable"
        current_primary_blocker = replay_blockers[0] if replay_blockers else "exact_replay_profitability"
        next_action = promotion_review.get("next_action") or "run_deferred_variant_sweeps_after_activation"
        next_command = variant_measurement_command
    elif not live_candidate_ready:
        status = "blocked_waiting_for_live_verifiable_candidate"
        primary_path_status = "exact_replay_profitable_waiting_for_live_candidate"
        current_primary_blocker = live_candidate_blockers[0] if live_candidate_blockers else "live_scan_has_verifiable_candidate"
        next_action = live_candidate_next_action
        next_command = live_candidate_next_command
    else:
        status = "blocked_by_source_or_completion_contract"
        primary_path_status = "blocked"
        current_primary_blocker = blockers[0] if blockers else "goal_completion_contract"
        next_action = "repair_source_or_completion_contract_before_goal_update"
        next_command = completion_contract_command
    ordered_unblock_plan = [
        {
            "phase": "source_and_proof_isolation",
            "status": "passed" if not source_contract_blockers else "blocked",
            "blockers": source_contract_blockers,
            "evidence_fields": [
                "provider",
                "proof_source_label",
                "proof_source_isolation_contract.status",
                "proof_source_isolation_contract.blockers",
            ],
            "next_action": None if not source_contract_blockers else "repair_source_or_completion_contract_before_goal_update",
            "next_command": None if not source_contract_blockers else source_contract_command,
            "next_command_role": None if not source_contract_blockers else "refresh_source_and_completion_contract",
            "not_before_user_local": None,
            "material_progress_if": [
                "proof_source_isolation_contract.status == isolated_to_alpaca_opra_proof_source",
                "proof_source_isolation_contract.blockers empty",
            ],
        },
        {
            "phase": "exact_opra_history_depth",
            "status": "passed" if not history_blockers else "blocked",
            "blockers": history_blockers,
            "evidence_fields": [
                "proof_window.current_shared_quote_dates",
                "proof_window.required_shared_quote_dates",
                "readiness.status",
                "exact_history_backfill_capability_audit.local_exact_store_usage_decision",
                "exact_history_backfill_capability_audit.local_exact_store_refresh_can_advance_history_depth",
                "exact_history_backfill_capability_audit.local_exact_available_shared_quote_dates",
                "exact_history_backfill_capability_audit.local_exact_store_matches_proof_window",
            ],
            "next_action": None if not history_blockers else history_depth_next_action,
            "next_command": None if not history_blockers else history_depth_command,
            "next_command_role": None if not history_blockers else history_depth_command_role,
            "not_before_user_local": None if not history_blockers else history_depth_not_before,
            "material_progress_if": [
                "proof_window.current_shared_quote_dates increases",
                "exact_history_acquisition_plan.remaining_shared_quote_dates decreases",
                "exact_history_backfill_capability_audit.local_exact_store_refresh_can_advance_history_depth true triggers refresh before waiting",
                "exact_history_backfill_capability_audit.local_exact_store_usage_decision == current_artifact_counts_all_local_alpaca_opra_shared_dates",
                "proof_source_isolation_contract.status stays isolated_to_alpaca_opra_proof_source",
            ],
        },
        {
            "phase": "exact_replay_profitability",
            "status": "passed" if exact_replay_ready and exact_replay_profitable else "blocked",
            "blockers": replay_blockers,
            "evidence_fields": [
                "verification_gate.replay_total_trades",
                "verification_gate.replay_profit_factor",
                "verification_gate.replay_total_return_pct",
            ],
            "next_action": None if exact_replay_ready and exact_replay_profitable else "run_exact_replay_after_required_history_depth",
            "next_command": None if exact_replay_ready and exact_replay_profitable else exact_replay_command,
            "next_command_role": None if exact_replay_ready and exact_replay_profitable else "exact_replay_profitability_measurement",
            "not_before_user_local": (
                None
                if exact_replay_ready
                else history_depth_runway.get("full_replay_unlock_not_before_user_local")
            ),
            "material_progress_if": [
                "verification_gate.replay_total_trades > 0",
                "verification_gate.replay_profit_factor > 1",
                "verification_gate.replay_total_return_pct > 0",
            ],
        },
        {
            "phase": "live_candidate_confirmation",
            "status": "passed" if live_candidate_ready else "blocked",
            "blockers": live_candidate_blockers,
            "evidence_fields": live_candidate_evidence_fields,
            "next_action": None if live_candidate_ready else live_candidate_next_action,
            "next_command": None if live_candidate_ready else live_candidate_next_command,
            "next_command_role": None if live_candidate_ready else live_candidate_next_command_role,
            "not_before_user_local": None if live_candidate_ready else live_candidate_not_before,
            "window_end_user_local": None if live_candidate_ready else live_candidate_window_end,
            "material_progress_if": live_candidate_material_progress,
            "auxiliary_evidence_opportunity": None if live_candidate_ready else first_auxiliary_evidence or None,
        },
        {
            "phase": "goal_completion_contract",
            "status": "passed" if verification.get("verified") is True and not blockers else "blocked",
            "blockers": blockers,
            "evidence_fields": [
                "goal_completion_audit.may_mark_goal_complete",
                "goal_completion_verification_contract.completion_claim_allowed",
            ],
            "next_action": None if verification.get("verified") is True and not blockers else "review_goal_completion_audit_after_all_prior_phases_pass",
            "next_command": None if verification.get("verified") is True and not blockers else completion_contract_command,
            "next_command_role": None if verification.get("verified") is True and not blockers else "completion_contract_readback",
            "not_before_user_local": None,
            "material_progress_if": [
                "goal_completion_audit.may_mark_goal_complete true",
                "goal_completion_verification_contract.completion_claim_allowed true",
            ],
        },
    ]
    return {
        "status": status,
        "primary_path_status": primary_path_status,
        "variant_path_status": promotion_review.get("status"),
        "current_primary_blocker": current_primary_blocker,
        "ordered_unblock_plan": ordered_unblock_plan,
        "exact_profitability_verified": verification.get("verified") is True,
        "baseline_exact_replay_ready": exact_replay_ready,
        "baseline_exact_replay_profitable": exact_replay_profitable,
        "live_candidate_ready": live_candidate_ready,
        "proof_source_isolation_status": proof_source_isolation.get("status"),
        "proof_source_isolation_blockers": proof_source_isolation.get("blockers"),
        "history_depth_runway": history_depth_runway,
        "current_shared_quote_dates": verification.get("current_shared_quote_dates"),
        "required_shared_quote_dates": verification.get("required_shared_quote_dates"),
        "replay_total_trades": verification.get("replay_total_trades"),
        "replay_profit_factor": verification.get("replay_profit_factor"),
        "replay_total_return_pct": verification.get("replay_total_return_pct"),
        "live_scan_candidate_count": verification.get("live_scan_candidate_count"),
        "checks": checks,
        "blockers": blockers,
        "promotion_review_blockers": promotion_review.get("blockers"),
        "next_action": next_action,
        "next_command": next_command,
        "proof_policy": "exact Alpaca SIP/OPRA replay plus live candidate inside exact proof universe required before completion",
    }


def attach_deferred_variant_result_collection(
    report: dict[str, Any],
    *,
    root: Path = ROOT,
    force: bool = False,
) -> dict[str, Any]:
    enriched = dict(report)
    existing_backlog = (
        enriched.get("post_fresh_scan_research_backlog")
        if isinstance(enriched.get("post_fresh_scan_research_backlog"), dict)
        else None
    )
    backlog = dict(existing_backlog) if existing_backlog is not None else build_post_fresh_scan_research_backlog(enriched)
    if (
        not force
        and isinstance(backlog.get("deferred_variant_result_collection"), dict)
    ):
        if not isinstance(backlog.get("deferred_variant_promotion_review"), dict):
            backlog["deferred_variant_promotion_review"] = build_deferred_variant_promotion_review(
                {**enriched, "post_fresh_scan_research_backlog": backlog},
                root=root,
            )
        enriched["post_fresh_scan_research_backlog"] = backlog
        return enriched
    collector_input = {**enriched, "post_fresh_scan_research_backlog": backlog}
    backlog["deferred_variant_result_collection"] = collect_deferred_variant_results(
        collector_input,
        root=root,
    )
    backlog["deferred_variant_promotion_review"] = build_deferred_variant_promotion_review(
        {**enriched, "post_fresh_scan_research_backlog": backlog},
        root=root,
    )
    enriched["post_fresh_scan_research_backlog"] = backlog
    return enriched


def _scan_pick_is_proof_eligible(pick: dict[str, Any]) -> bool:
    def _normalized(value: Any) -> str:
        return str(value or "").strip().lower().replace("-", "_").replace(" ", "_")

    explicit_proof_evidence = any(
        pick.get(field) is True
        for field in (
            "proof_eligible",
            "counts_for_exact_profitability_proof",
            "counts_for_goal_verification",
            "used_for_goal_verification",
            "used_for_exact_profitability_proof",
        )
    )
    if pick.get("proof_eligible") is False:
        return False
    if pick.get("research_only") is True or pick.get("diagnostic_only") is True:
        return False
    if pick.get("counts_for_exact_profitability_proof") is False:
        return False
    if pick.get("counts_for_goal_verification") is False:
        return False
    if pick.get("used_for_goal_verification") is False:
        return False
    if pick.get("promotion_allowed") is False:
        return False
    guardrail_decision = _normalized(pick.get("guardrail_decision") or "clear")
    if guardrail_decision == "blocked":
        return False
    managed_decision = _normalized(pick.get("managed_lane_decision"))
    if managed_decision in {"blocked", "watch", "research_only", "diagnostic"}:
        return False
    policy_decision = _normalized(pick.get("trade_policy_decision") or pick.get("policy_decision"))
    if policy_decision and policy_decision not in {"approved", "clear"}:
        return False
    for field in (
        "status",
        "lane_status",
        "candidate_status",
        "evidence_role",
        "purpose",
        "usage",
        "source_role",
    ):
        value = _normalized(pick.get(field))
        if any(token in value for token in ("research_only", "diagnostic", "non_verifying")):
            return False
    source_values = [
        pick.get("candidate_execution_label"),
        pick.get("market_data_source"),
        pick.get("options_market_data_source"),
        pick.get("source_label"),
        pick.get("proof_source_label"),
        pick.get("data_source"),
    ]
    proof_grade_source_values = {
        "executable_opra_paper_candidate",
        "alpaca_opra",
        ALPACA_OPRA_SOURCE_LABEL,
    }
    proof_grade_source = any(
        _normalized(value) in proof_grade_source_values
        for value in source_values
    )
    return proof_grade_source


def _scan_summary(result: dict[str, Any]) -> dict[str, Any]:
    playbook = result.get("playbook") or {}
    scan_drop_reasons = result.get("scan_drop_reasons") or {}
    drop_counts = (((result.get("scan_funnel") or {}).get("drop_counts")) or {})
    blocker_examples = _scan_blocker_examples(scan_drop_reasons)
    drop_reason_audit = _scan_drop_reason_audit(scan_drop_reasons)
    quote_freshness_context = _scan_quote_freshness_context(blocker_examples)
    gate_sensitivity = _scan_gate_sensitivity(blocker_examples)
    if quote_freshness_context.get("status") in {"stale_quote_sensitive", "stale_quote_blocked"}:
        gate_sensitivity["recommended_action"] = quote_freshness_context.get("recommended_action")
    pick_sources = (
        list(result.get("picks") or [])
        + list(result.get("ranked_picks") or [])
        + list(result.get("candidate_audit_picks") or [])
    )
    candidate_symbols = sorted(
        {
            str(pick.get("ticker") or pick.get("symbol") or "").strip().upper()
            for pick in pick_sources
            if isinstance(pick, dict) and str(pick.get("ticker") or pick.get("symbol") or "").strip()
        }
    )
    proof_candidate_source = (
        list(result.get("candidate_audit_picks") or [])
        or list(result.get("ranked_picks") or [])
        or list(result.get("picks") or [])
    )
    proof_eligible_picks = [
        pick for pick in proof_candidate_source if isinstance(pick, dict) and _scan_pick_is_proof_eligible(pick)
    ]
    proof_eligible_candidate_symbols = sorted(
        {
            str(pick.get("ticker") or pick.get("symbol") or "").strip().upper()
            for pick in proof_eligible_picks
            if str(pick.get("ticker") or pick.get("symbol") or "").strip()
        }
    )
    return {
        "candidate_count": result.get("candidate_count"),
        "raw_candidate_count": result.get("candidate_count"),
        "returned_count": result.get("returned_count"),
        "candidate_symbols": candidate_symbols,
        "raw_candidate_symbols": candidate_symbols,
        "proof_eligible_candidate_count": len(proof_eligible_picks),
        "proof_eligible_candidate_symbols": proof_eligible_candidate_symbols,
        "scan_funnel": result.get("scan_funnel"),
        "guardrail_decision_counts": result.get("guardrail_decision_counts"),
        **drop_reason_audit,
        "blocker_examples": blocker_examples,
        "drop_diagnostics": _ranked_scan_drop_diagnostics(scan_drop_reasons, drop_counts),
        "blocker_symbols": sorted(
            {
                str(item.get("symbol") or "").strip().upper()
                for item in blocker_examples
                if str(item.get("symbol") or "").strip()
            }
        ),
        "gate_sensitivity": gate_sensitivity,
        "quote_freshness_context": quote_freshness_context,
        "playbook_scan_tickers": list(playbook.get("scan_tickers") or []),
        "playbook_allowed_tickers": list(playbook.get("allowed_tickers") or []),
        "historical_data_ready_tickers": list(playbook.get("historical_data_ready_tickers") or []),
        "historical_data_readiness_status": playbook.get("historical_data_readiness_status"),
        "historical_core_ready_count": playbook.get("historical_core_ready_count"),
        "historical_core_required_count": playbook.get("historical_core_required_count"),
        "historical_scan_ready_count": playbook.get("historical_scan_ready_count"),
        "historical_scan_required_count": playbook.get("historical_scan_required_count"),
    }


def annotate_scan_quote_freshness_timing(
    scan: dict[str, Any] | None,
    *,
    now_utc: datetime,
) -> dict[str, Any] | None:
    if scan is None:
        return None
    enriched = dict(scan)
    quote_freshness = dict(enriched.get("quote_freshness_context") or {})
    if quote_freshness.get("status") in {"stale_quote_sensitive", "stale_quote_blocked"}:
        fresh_scan = next_fresh_scan_time(now_utc=now_utc, user_timezone_name=_runbook_timezone_name())
        quote_freshness["next_fresh_scan"] = fresh_scan
        enriched["quote_freshness_context"] = quote_freshness
        gate_sensitivity = dict(enriched.get("gate_sensitivity") or {})
        gate_sensitivity["next_fresh_scan_utc"] = fresh_scan.get("scheduled_utc")
        gate_sensitivity["next_fresh_scan_local"] = fresh_scan.get("scheduled_local")
        gate_sensitivity["next_fresh_scan_user_local"] = fresh_scan.get("scheduled_user_local")
        enriched["gate_sensitivity"] = gate_sensitivity
        retest_plan = _fresh_scan_retest_plan(enriched)
        if retest_plan:
            enriched["fresh_scan_retest_plan"] = retest_plan
    if "scan_drop_reason_audit_status" not in enriched:
        enriched["scan_drop_reason_audit_status"] = "waiting_for_next_scan_result_with_raw_drop_reasons"
    return enriched


def build_source_quality_summary(readiness: dict[str, Any]) -> dict[str, Any]:
    summary = readiness.get("summary") if isinstance(readiness.get("summary"), dict) else {}
    health = (
        readiness.get("required_underlying_health")
        if isinstance(readiness.get("required_underlying_health"), dict)
        else {}
    )
    required_underlyings = [str(symbol).upper() for symbol in readiness.get("required_underlyings") or []]
    per_symbol: list[dict[str, Any]] = []
    for symbol in required_underlyings:
        row = health.get(symbol) if isinstance(health.get(symbol), dict) else {}
        per_symbol.append(
            {
                "symbol": symbol,
                "quote_rows": int(row.get("quote_rows") or 0),
                "contract_count": int(row.get("contract_count") or 0),
                "quote_date_count": int(row.get("quote_date_count") or 0),
                "executable_quote_pct": _number_or_none(row.get("executable_quote_pct")),
                "missing_bid_ask_rows": int(row.get("missing_bid_ask_rows") or 0),
                "crossed_quote_rows": int(row.get("crossed_quote_rows") or 0),
                "underlying_price_pct": _number_or_none(row.get("underlying_price_pct")),
            }
        )
    executable_values = [
        float(item["executable_quote_pct"]) for item in per_symbol if item.get("executable_quote_pct") is not None
    ]
    underlying_price_values = [
        float(item["underlying_price_pct"]) for item in per_symbol if item.get("underlying_price_pct") is not None
    ]
    lowest_quote_rows = sorted(per_symbol, key=lambda item: (int(item.get("quote_rows") or 0), item["symbol"]))[:5]
    missing_required = list(readiness.get("missing_required_underlyings") or [])
    low_executable = list(readiness.get("low_executable_required_underlyings") or [])
    shared = readiness.get("shared_required_quote_dates") if isinstance(readiness.get("shared_required_quote_dates"), dict) else {}
    minimums = readiness.get("minimums") if isinstance(readiness.get("minimums"), dict) else {}
    shared_count = int(shared.get("count") or 0)
    min_shared_count = int(minimums.get("min_shared_quote_dates") or 0)
    if missing_required:
        quality_status = "missing_required_underlyings"
    elif low_executable:
        quality_status = "low_executable_quote_coverage"
    elif not per_symbol:
        quality_status = "no_required_underlying_health"
    elif shared_count < min_shared_count:
        quality_status = "usable_quotes_waiting_for_history_depth"
    else:
        quality_status = "source_quality_ready"

    return {
        "status": quality_status,
        "source_labels_required": readiness.get("source_labels_required") or [],
        "snapshot_kind": readiness.get("snapshot_kind"),
        "total_quote_rows": int(summary.get("quote_count") or sum(int(item.get("quote_rows") or 0) for item in per_symbol)),
        "batch_count": int(summary.get("batch_count") or 0),
        "earliest_quote_at_utc": summary.get("earliest_quote_at_utc"),
        "latest_quote_at_utc": summary.get("latest_quote_at_utc"),
        "latest_imported_at_utc": summary.get("latest_imported_at_utc"),
        "required_underlying_count": len(required_underlyings),
        "available_required_underlying_count": len(required_underlyings) - len(missing_required),
        "missing_required_underlyings": missing_required,
        "low_executable_required_underlyings": low_executable,
        "min_executable_quote_pct": round(min(executable_values), 2) if executable_values else None,
        "min_underlying_price_pct": round(min(underlying_price_values), 2) if underlying_price_values else None,
        "total_missing_bid_ask_rows": sum(int(item.get("missing_bid_ask_rows") or 0) for item in per_symbol),
        "total_crossed_quote_rows": sum(int(item.get("crossed_quote_rows") or 0) for item in per_symbol),
        "lowest_quote_row_symbols": lowest_quote_rows,
    }


def build_scan_proof_universe_alignment(
    *,
    proof_symbols: Iterable[str],
    scan_symbols: Iterable[str],
    scan: dict[str, Any] | None,
) -> dict[str, Any]:
    proof_list = [str(symbol).strip().upper() for symbol in proof_symbols if str(symbol).strip()]
    scan_list = [str(symbol).strip().upper() for symbol in scan_symbols if str(symbol).strip()]
    proof_list = list(dict.fromkeys(proof_list))
    scan_list = list(dict.fromkeys(scan_list))
    proof_set = set(proof_list)
    scan_payload = scan or {}
    candidate_symbols = [
        str(symbol).strip().upper()
        for symbol in (scan_payload.get("candidate_symbols") or [])
        if str(symbol).strip()
    ]
    proof_eligible_candidate_symbols = [
        str(symbol).strip().upper()
        for symbol in (
            scan_payload.get("proof_eligible_candidate_symbols")
            if scan_payload.get("proof_eligible_candidate_symbols") is not None
            else candidate_symbols
        )
        if str(symbol).strip()
    ]
    blocker_symbols = [
        str(symbol).strip().upper()
        for symbol in (scan_payload.get("blocker_symbols") or [])
        if str(symbol).strip()
    ]
    candidate_symbols = list(dict.fromkeys(candidate_symbols))
    proof_eligible_candidate_symbols = list(dict.fromkeys(proof_eligible_candidate_symbols))
    blocker_symbols = list(dict.fromkeys(blocker_symbols))
    candidate_outside = [symbol for symbol in proof_eligible_candidate_symbols if symbol not in proof_set]
    blocker_outside = [symbol for symbol in blocker_symbols if symbol not in proof_set]
    scan_without_proof = [symbol for symbol in scan_list if symbol not in proof_set]
    raw_candidate_count = int(scan_payload.get("candidate_count") or 0)
    candidate_count = int(
        scan_payload.get("proof_eligible_candidate_count")
        if scan_payload.get("proof_eligible_candidate_count") is not None
        else raw_candidate_count
    )
    candidate_symbols_available = bool(proof_eligible_candidate_symbols) or candidate_count == 0
    candidates_inside = candidate_count > 0 and candidate_symbols_available and not candidate_outside
    if not scan_payload:
        status = "scan_skipped"
        next_action = "run_scan_to_check_candidate_universe_alignment"
    elif scan_without_proof:
        status = "scan_universe_exceeds_exact_proof_universe"
        next_action = "expand_exact_alpaca_opra_capture_to_scan_universe_or_treat_outside_symbols_as_research_only"
    else:
        status = "scan_universe_aligned_with_exact_proof_universe"
        next_action = "live_scan_candidates_can_count_if_other_gates_pass"
    return {
        "status": status,
        "proof_universe": proof_list,
        "proof_universe_count": len(proof_list),
        "scan_universe": scan_list,
        "scan_universe_count": len(scan_list),
        "scan_symbols_without_exact_proof": scan_without_proof,
        "scan_symbols_without_exact_proof_count": len(scan_without_proof),
        "candidate_symbols": candidate_symbols,
        "raw_candidate_count": raw_candidate_count,
        "raw_candidate_symbols": scan_payload.get("raw_candidate_symbols") or candidate_symbols,
        "proof_eligible_candidate_count": candidate_count,
        "proof_eligible_candidate_symbols": proof_eligible_candidate_symbols,
        "candidate_symbols_outside_exact_proof": candidate_outside,
        "candidate_symbols_available": candidate_symbols_available,
        "live_scan_candidates_all_inside_exact_proof": candidates_inside,
        "blocker_symbols": blocker_symbols,
        "blocker_symbols_outside_exact_proof": blocker_outside,
        "blocker_symbols_outside_exact_proof_count": len(blocker_outside),
        "next_action": next_action,
    }


def build_capture_action_summary(report: dict[str, Any]) -> dict[str, Any]:
    proof_window = report.get("proof_window") or {}
    capture = report.get("capture") or {}
    automation = report.get("automation_health") or {}
    remaining = int(proof_window.get("remaining_shared_quote_dates") or 0)
    current_target = proof_window.get("current_target_trade_date")
    next_missing = proof_window.get("next_missing_capture_trade_date")
    missed_dates = list(proof_window.get("missed_capture_trade_dates_since_latest_shared") or [])
    current_target_captured = proof_window.get("current_target_captured") is True
    capture_status = str(capture.get("status") or "")
    capture_target_complete = capture.get("target_capture_complete")
    capture_missing_after = list(capture.get("missing_target_date_symbols_after") or [])
    automation_healthy = automation.get("healthy") is True
    schedule = scheduled_capture_time_for_trade_date(
        str(next_missing) if next_missing else None,
        rrule=automation.get("rrule"),
        timezone_name=os.getenv("AI_COMMODITY_CAPTURE_TIMEZONE", DEFAULT_CAPTURE_SCHEDULE_TIMEZONE),
    )
    reference_now = _parse_utc_datetime(report.get("generated_at")) or _utc_now()
    schedule = annotate_scheduled_capture_timing(schedule, now_utc=reference_now)

    status = "unknown"
    next_action = "rerun_progress_report"
    can_attempt_capture_now = False
    waiting_on_future_market_day = False

    if remaining <= 0:
        status = "complete"
        next_action = "run_exact_replay_and_profitability_gate"
    elif not automation_healthy:
        status = "automation_unhealthy"
        next_action = "repair_or_reenable_capture_automation"
    elif capture_status.startswith("blocked_"):
        status = "capture_blocked"
        next_action = f"fix_capture_blocker:{capture_status}"
        can_attempt_capture_now = True
    elif capture_target_complete is False:
        status = "capture_incomplete_for_target"
        symbol_suffix = ",".join(capture_missing_after[:10])
        if len(capture_missing_after) > 10:
            symbol_suffix = f"{symbol_suffix},+{len(capture_missing_after) - 10}more"
        next_action = f"recapture_missing_symbols_for_target:{current_target}:{symbol_suffix}"
        can_attempt_capture_now = True
    elif missed_dates:
        status = "intervention_required_missed_capture_dates"
        next_action = "record_missed_capture_dates_keep_goal_incomplete_and_resume_forward_capture"
        can_attempt_capture_now = True
    elif not current_target_captured:
        status = "capture_due_for_current_target"
        next_action = f"run_capture_for_current_target:{current_target}"
        can_attempt_capture_now = True
    elif current_target and next_missing and str(next_missing) > str(current_target):
        status = "waiting_for_next_market_close"
        next_action = f"wait_until_next_missing_date_is_capturable:{next_missing}"
        waiting_on_future_market_day = True
    else:
        status = "on_track"
        next_action = "continue_daily_capture_loop"

    return {
        "status": status,
        "next_action": next_action,
        "can_attempt_capture_now": can_attempt_capture_now,
        "waiting_on_future_market_day": waiting_on_future_market_day,
        "capture_calendar": proof_window.get("capture_calendar") or "us_equity_market_days",
        "holiday_calendar_source": proof_window.get("holiday_calendar_source")
        or "NYSE/Nasdaq US equity market holiday rules",
        "current_target_trade_date": current_target,
        "current_target_captured": current_target_captured,
        "next_missing_capture_trade_date": next_missing,
        "remaining_shared_quote_dates": remaining,
        "missed_capture_trade_dates": missed_dates,
        "missed_capture_policy": MISSED_OPRA_BBO_CAPTURE_POLICY,
        "missed_capture_recovery_action": (
            "resume_forward_capture_from_next_missing_trade_date_without_counting_missed_dates"
            if missed_dates
            else None
        ),
        "missed_capture_dates_recoverable": False if missed_dates else None,
        "capture_status": capture_status,
        "capture_target_complete": capture_target_complete,
        "capture_missing_target_symbols_after": capture_missing_after,
        "automation_healthy": automation_healthy,
        "next_scheduled_capture": schedule,
    }


def build_verified_profitability_gate(report: dict[str, Any]) -> dict[str, Any]:
    proof_window = report.get("proof_window") or {}
    automation = report.get("automation_health") or {}
    source_quality = report.get("source_quality") or {}
    readiness = report.get("readiness") or {}
    replay = report.get("replay") or {}
    scan = report.get("scan") or {}
    scan_alignment = report.get("scan_proof_universe_alignment") or {}
    capture = report.get("capture") or {}
    provider = str(report.get("provider") or "")
    proof_source = report.get("proof_source_label") or proof_window.get("source_label")

    current_shared = int(proof_window.get("current_shared_quote_dates") or 0)
    required_shared = int(proof_window.get("required_shared_quote_dates") or 0)
    replay_error = replay.get("error")
    raw_candidate_count = int(scan.get("candidate_count") or 0)
    candidate_count = int(
        scan.get("proof_eligible_candidate_count")
        if scan.get("proof_eligible_candidate_count") is not None
        else scan_alignment.get("proof_eligible_candidate_count")
        if scan_alignment.get("proof_eligible_candidate_count") is not None
        else raw_candidate_count
    )
    scan_universe_count = int(scan_alignment.get("scan_universe_count") or 0)
    proof_universe_count = int(scan_alignment.get("proof_universe_count") or 0)
    capture_symbol_count = int(capture.get("symbol_count") or 0)
    proof_scan_universe_aligned = (
        scan_alignment.get("status") == "scan_universe_aligned_with_exact_proof_universe"
        and scan_universe_count > 0
        and proof_universe_count == scan_universe_count
    )
    capture_scope_full_scan_universe = (
        capture.get("scope") == "ai_commodity_scan_universe"
        and scan_universe_count > 0
        and capture_symbol_count == scan_universe_count
    )
    capture_target_complete = capture.get("target_capture_complete") is True
    if scan_alignment:
        live_candidate_inside_proof_universe = scan_alignment.get("live_scan_candidates_all_inside_exact_proof") is True
    else:
        live_candidate_inside_proof_universe = False
    replay_profit_factor = _number_or_none(replay.get("profit_factor"))
    replay_total_trades = int(replay.get("total_trades") or 0)
    replay_total_return = _number_or_none(replay.get("total_return_pct"))
    source_quality_status = source_quality.get("status")
    source_quality_usable = source_quality_status in SOURCE_QUALITY_USABLE_STATUSES

    gates = {
        "alpaca_sip_opra_provider": provider == "alpaca:sip:opra",
        "alpaca_opra_source_filtered": proof_source == ALPACA_OPRA_SOURCE_LABEL,
        "capture_automation_healthy": automation.get("healthy") is True,
        "capture_scope_full_scan_universe": capture_scope_full_scan_universe,
        "capture_target_complete": capture_target_complete,
        "proof_scan_universe_aligned": proof_scan_universe_aligned,
        "alpaca_opra_source_quality_usable": source_quality_usable,
        "enough_exact_shared_quote_dates": required_shared > 0 and current_shared >= required_shared,
        "readiness_ready_for_exact_replay": readiness.get("status") == "ready_for_exact_replay",
        "exact_replay_completed": not replay_error,
        "exact_replay_has_trades": replay_total_trades > 0,
        "exact_replay_profit_factor_positive": replay_profit_factor is not None and replay_profit_factor > 1.0,
        "exact_replay_total_return_positive": replay_total_return is not None and replay_total_return > 0.0,
        "live_scan_has_candidate": candidate_count > 0,
        "live_scan_candidate_inside_exact_proof_universe": live_candidate_inside_proof_universe,
    }
    blockers: list[str] = []
    if not gates["alpaca_sip_opra_provider"]:
        blockers.append(f"provider_not_alpaca_sip_opra:{provider}")
    if not gates["alpaca_opra_source_filtered"]:
        blockers.append(f"proof_source_not_alpaca_opra:{proof_source}")
    if not gates["capture_automation_healthy"]:
        blockers.append(f"capture_automation:{automation.get('blocker') or automation.get('status')}")
    if not gates["capture_scope_full_scan_universe"]:
        blockers.append(
            "capture_scope_not_full_scan_universe:"
            f"{capture.get('scope') or 'missing'}:{capture_symbol_count}/{scan_universe_count or 'unknown'}"
        )
    if not gates["capture_target_complete"]:
        missing_after = capture.get("missing_target_date_symbols_after") or []
        blockers.append(f"capture_target_incomplete:{missing_after or 'unknown'}")
    if not gates["proof_scan_universe_aligned"]:
        blockers.append(
            "proof_scan_universe_not_aligned:"
            f"{scan_alignment.get('status') or 'missing'}:{proof_universe_count}/{scan_universe_count or 'unknown'}"
        )
    if not gates["alpaca_opra_source_quality_usable"]:
        blockers.append(f"source_quality:{source_quality_status}")
    if not gates["enough_exact_shared_quote_dates"]:
        blockers.append(f"shared_quote_dates:{current_shared}/{required_shared}")
    if not gates["readiness_ready_for_exact_replay"]:
        blockers.append(f"readiness:{readiness.get('blocker') or readiness.get('status')}")
    if not gates["exact_replay_completed"]:
        blockers.append(f"replay_error:{replay_error}")
    if gates["exact_replay_completed"] and not gates["exact_replay_has_trades"]:
        blockers.append("replay_trades:0")
    if gates["exact_replay_completed"] and not gates["exact_replay_profit_factor_positive"]:
        blockers.append(f"profit_factor:{replay.get('profit_factor')}")
    if gates["exact_replay_completed"] and not gates["exact_replay_total_return_positive"]:
        blockers.append(f"total_return_pct:{replay.get('total_return_pct')}")
    if not gates["live_scan_has_candidate"]:
        blockers.append(f"live_scan_candidates:{candidate_count}")
    elif not gates["live_scan_candidate_inside_exact_proof_universe"]:
        if not scan_alignment:
            blockers.append("live_scan_candidate_inside_exact_proof_universe_missing_scan_proof_universe_alignment")
        else:
            outside_symbols = scan_alignment.get("candidate_symbols_outside_exact_proof") or []
            blockers.append(f"live_scan_candidate_outside_exact_proof_universe:{outside_symbols or 'unknown'}")

    return {
        "status": "verified_profitable" if all(gates.values()) else "not_verified",
        "verified": all(gates.values()),
        "gates": gates,
        "blockers": blockers,
        "current_shared_quote_dates": current_shared,
        "required_shared_quote_dates": required_shared,
        "replay_profit_factor": replay.get("profit_factor"),
        "replay_total_return_pct": replay.get("total_return_pct"),
        "replay_total_trades": replay.get("total_trades"),
        "live_scan_candidate_count": candidate_count,
        "live_scan_candidate_symbols": (
            scan_alignment.get("proof_eligible_candidate_symbols")
            or scan.get("proof_eligible_candidate_symbols")
            or scan_alignment.get("candidate_symbols")
            or scan.get("candidate_symbols")
        ),
        "raw_live_scan_candidate_count": raw_candidate_count,
        "raw_live_scan_candidate_symbols": scan.get("raw_candidate_symbols") or scan.get("candidate_symbols"),
        "proof_eligible_candidate_count": candidate_count,
        "proof_eligible_candidate_symbols": (
            scan_alignment.get("proof_eligible_candidate_symbols")
            or scan.get("proof_eligible_candidate_symbols")
            or []
        ),
        "source_quality_status": source_quality_status,
        "capture_scope": capture.get("scope"),
        "capture_symbol_count": capture_symbol_count,
        "proof_universe_count": proof_universe_count,
        "scan_universe_count": scan_universe_count,
    }


def _next_timed_lane_event(
    *,
    capture_action: dict[str, Any],
    scan_quote_freshness: dict[str, Any],
) -> dict[str, Any] | None:
    events: list[dict[str, Any]] = []
    next_fresh_scan = scan_quote_freshness.get("next_fresh_scan") or {}
    if scan_quote_freshness.get("status") in {"stale_quote_sensitive", "stale_quote_blocked"}:
        event_utc_value = (
            next_fresh_scan.get("reference_utc")
            if next_fresh_scan.get("can_attempt_scan_now") is True
            else next_fresh_scan.get("scheduled_utc")
        )
        scheduled_utc = _parse_utc_datetime(event_utc_value)
        if scheduled_utc is not None:
            events.append(
                {
                    "kind": "fresh_opra_scan",
                    "action": scan_quote_freshness.get("recommended_action")
                    or "rerun_live_scan_during_fresh_opra_window",
                    "scheduled_utc": event_utc_value,
                    "scheduled_local": next_fresh_scan.get("scheduled_local"),
                    "scheduled_market_local": next_fresh_scan.get("scheduled_market_local"),
                    "scheduled_user_local": next_fresh_scan.get("scheduled_user_local"),
                    "scan_calendar": next_fresh_scan.get("scan_calendar"),
                    "holiday_calendar_source": next_fresh_scan.get("holiday_calendar_source"),
                    "scheduled_trade_date_is_market_day": next_fresh_scan.get(
                        "scheduled_trade_date_is_market_day"
                    ),
                    "market_timezone": next_fresh_scan.get("market_timezone"),
                    "user_timezone": next_fresh_scan.get("user_timezone"),
                    "hours_until_scheduled": next_fresh_scan.get("hours_until_scheduled"),
                    "timing_status": next_fresh_scan.get("status"),
                    "can_attempt_now": next_fresh_scan.get("can_attempt_scan_now"),
                    "window_start_utc": next_fresh_scan.get("window_start_utc"),
                    "window_end_utc": next_fresh_scan.get("window_end_utc"),
                    "window_start_market_local": next_fresh_scan.get("window_start_market_local"),
                    "window_start_user_local": next_fresh_scan.get("window_start_user_local"),
                    "window_end_market_local": next_fresh_scan.get("window_end_market_local"),
                    "window_end_user_local": next_fresh_scan.get("window_end_user_local"),
                    "_sort_utc": scheduled_utc,
                }
            )
    scheduled_capture = capture_action.get("next_scheduled_capture") or {}
    if capture_action.get("status") == "waiting_for_next_market_close":
        scheduled_utc = _parse_utc_datetime(scheduled_capture.get("scheduled_utc"))
        if scheduled_utc is not None:
            events.append(
                {
                    "kind": "post_close_opra_capture",
                    "action": capture_action.get("next_action") or "wait_for_next_post_close_capture",
                    "scheduled_utc": scheduled_capture.get("scheduled_utc"),
                    "scheduled_local": scheduled_capture.get("scheduled_local"),
                    "hours_until_scheduled": scheduled_capture.get("hours_until_scheduled"),
                    "_sort_utc": scheduled_utc,
                }
            )
    if not events:
        return None
    selected = min(events, key=lambda item: item["_sort_utc"])
    selected.pop("_sort_utc", None)
    return selected


def build_lane_next_step_summary(report: dict[str, Any]) -> dict[str, Any]:
    proof_window = report.get("proof_window") or {}
    capture_action = report.get("capture_action") or {}
    verification = report.get("verification_gate") or {}
    gates = verification.get("gates") if isinstance(verification.get("gates"), dict) else {}
    readiness = report.get("readiness") or {}
    replay = report.get("replay") or {}
    diagnostic_replay = report.get("diagnostic_replay") or {}
    scan = report.get("scan") or {}
    scan_quote_freshness = scan.get("quote_freshness_context") or {}
    preserved_evidence_refresh = (
        report.get("preserved_evidence_refresh")
        if isinstance(report.get("preserved_evidence_refresh"), dict)
        else {}
    )
    if not preserved_evidence_refresh:
        derived_refresh = report.get("derived_refresh") if isinstance(report.get("derived_refresh"), dict) else {}
        preserved_evidence_refresh = {
            "stale_after_historical_store_refresh": derived_refresh.get(
                "preserved_evidence_stale_after_historical_store_refresh"
            ),
            "stale_fields": derived_refresh.get("preserved_evidence_stale_fields") or [],
            "command": derived_refresh.get("preserved_evidence_refresh_command"),
            "reason": derived_refresh.get("preserved_evidence_refresh_reason"),
        }
    current_shared = int(proof_window.get("current_shared_quote_dates") or 0)
    required_shared = max(int(proof_window.get("required_shared_quote_dates") or 0), 1)
    diagnostic_ready = proof_window.get("diagnostic_ready") is True
    blocked_gates = [name for name, passed in sorted(gates.items()) if passed is False]
    scheduled_capture = capture_action.get("next_scheduled_capture") or {}
    verification_blockers = list(verification.get("blockers") or [])
    diagnostic_blockers = list(diagnostic_replay.get("blockers") or [])
    next_timed_event = _next_timed_lane_event(
        capture_action=capture_action,
        scan_quote_freshness=scan_quote_freshness,
    )
    fresh_scan_due_now = (
        (next_timed_event or {}).get("kind") == "fresh_opra_scan"
        and (next_timed_event or {}).get("can_attempt_now") is True
    )

    phase = "unknown"
    priority_action = "rerun_progress_report"
    primary_blocker = verification_blockers[0] if verification_blockers else None
    rationale: list[str] = []

    if preserved_evidence_refresh.get("stale_after_historical_store_refresh") is True and not fresh_scan_due_now:
        phase = "preserved_evidence_refresh"
        priority_action = "refresh_readiness_replay_after_historical_store_change"
        primary_blocker = "preserved_readiness_replay_stale_after_historical_store_refresh"
        next_timed_event = None
        rationale.append(
            "Local Alpaca OPRA shared-date history changed, so preserved readiness/replay evidence must be refreshed before it can steer profitability decisions."
        )
        if preserved_evidence_refresh.get("stale_fields"):
            rationale.append(f"Stale preserved fields: {preserved_evidence_refresh.get('stale_fields')}.")
    elif verification.get("verified") is True:
        phase = "verified_profitable"
        priority_action = "prepare_promotion_or_live_monitoring"
        primary_blocker = None
    elif gates.get("alpaca_sip_opra_provider") is False or gates.get("alpaca_opra_source_filtered") is False:
        phase = "source_wiring"
        priority_action = "restore_alpaca_sip_opra_source_filtering"
        rationale.append("Alpaca SIP/OPRA source gates must pass before any profitability work counts.")
    elif gates.get("capture_automation_healthy") is False:
        phase = "capture_automation"
        priority_action = "repair_or_reenable_capture_automation"
        rationale.append("Daily exact OPRA evidence cannot accumulate without a healthy capture loop.")
    elif (
        gates.get("capture_scope_full_scan_universe") is False
        or gates.get("capture_target_complete") is False
        or gates.get("proof_scan_universe_aligned") is False
    ):
        phase = "proof_universe_alignment"
        primary_blocker = next(
            (
                blocker
                for blocker in verification_blockers
                if str(blocker).startswith(
                    (
                        "capture_scope_not_full_scan_universe:",
                        "capture_target_incomplete:",
                        "proof_scan_universe_not_aligned:",
                    )
                )
            ),
            primary_blocker,
        )
        priority_action = "repair_full_scan_universe_capture_and_proof_alignment"
        rationale.append("Full-universe capture/proof alignment must pass before waiting for more OPRA dates.")
    elif gates.get("alpaca_opra_source_quality_usable") is False:
        phase = "source_quality"
        priority_action = "repair_alpaca_opra_quote_quality_or_required_underlying_coverage"
        rationale.append("Exact replay requires usable bid/ask OPRA coverage across required underlyings.")
    elif preserved_evidence_refresh.get("stale_after_historical_store_refresh") is True and fresh_scan_due_now:
        phase = "fresh_scan_due_preserved_evidence_stale"
        priority_action = (next_timed_event or {}).get("action") or "rerun_live_scan_during_fresh_opra_window"
        primary_blocker = "live_scan_candidates:0_stale_quote_sensitive"
        rationale.append(
            "The fresh OPRA scan window is active, so capture the time-sensitive live scan evidence before refreshing preserved readiness/replay evidence."
        )
        if preserved_evidence_refresh.get("stale_fields"):
            rationale.append(f"Preserved fields still need refresh after the scan: {preserved_evidence_refresh.get('stale_fields')}.")
    elif current_shared < required_shared:
        primary_blocker = f"shared_quote_dates:{current_shared}/{required_shared}"
        if capture_action.get("can_attempt_capture_now") is True:
            phase = "capture_due"
            priority_action = capture_action.get("next_action") or "run_current_opra_capture"
        elif diagnostic_ready and diagnostic_blockers:
            phase = "diagnostic_replay_checkpoint"
            priority_action = diagnostic_replay.get("next_action") or "inspect_diagnostic_replay_blockers"
            primary_blocker = diagnostic_blockers[0]
        elif (next_timed_event or {}).get("kind") == "fresh_opra_scan":
            phase = "fresh_scan_wait"
            priority_action = (next_timed_event or {}).get("action") or "rerun_live_scan_during_fresh_opra_window"
        elif capture_action.get("status") == "waiting_for_next_market_close":
            phase = "capture_wait"
            priority_action = capture_action.get("next_action") or "wait_for_next_post_close_capture"
        else:
            phase = "capture_accumulation"
            priority_action = capture_action.get("next_action") or "continue_daily_capture_loop"
        rationale.append("Full verification is blocked until the exact Alpaca OPRA shared-date gate passes.")
        rationale.append("Production filters should stay fixed until exact OPRA replay has enough history.")
        if diagnostic_replay.get("next_action"):
            rationale.append(f"Diagnostic replay next action: {diagnostic_replay.get('next_action')}.")
        if diagnostic_ready:
            rationale.append("Diagnostic replay has enough shared OPRA dates for early signal checks, but not full verification.")
        if scan_quote_freshness.get("status") in {"stale_quote_sensitive", "stale_quote_blocked"}:
            rationale.append(
                "The zero-candidate live scan is quote-age sensitive; rerun during a fresh OPRA window before changing filters."
            )
        if (next_timed_event or {}).get("kind") == "fresh_opra_scan":
            rationale.append("The fresh OPRA scan window is the next timed lane event before the post-close capture.")
    elif readiness.get("status") != "ready_for_exact_replay":
        phase = "readiness"
        priority_action = "repair_paid_data_readiness_for_exact_replay"
        primary_blocker = f"readiness:{readiness.get('blocker') or readiness.get('status')}"
    elif replay.get("error"):
        phase = "exact_replay_error"
        priority_action = "debug_exact_alpaca_opra_replay_error"
        primary_blocker = f"replay_error:{replay.get('error')}"
    elif int(replay.get("total_trades") or 0) <= 0:
        phase = "exact_replay_no_trades"
        priority_action = "inspect_replay_signal_filters_and_trade_generation"
        primary_blocker = "replay_trades:0"
    elif (
        int(scan.get("candidate_count") or 0) <= 0
        and scan_quote_freshness.get("status") in {"stale_quote_sensitive", "stale_quote_blocked"}
    ):
        phase = "live_scan_freshness"
        priority_action = scan_quote_freshness.get("recommended_action") or "rerun_live_scan_during_fresh_opra_window"
        primary_blocker = "live_scan_candidates:0_stale_quote_sensitive"
    elif int(scan.get("candidate_count") or 0) <= 0:
        phase = "live_scan_candidates"
        priority_action = "inspect_live_scan_blocker_examples_without_relaxing_production_filters"
        primary_blocker = "live_scan_candidates:0"
    elif not gates.get("exact_replay_profit_factor_positive") or not gates.get("exact_replay_total_return_positive"):
        phase = "profitability_tuning"
        priority_action = "tune_lane_using_exact_opra_replay_metrics"
        primary_blocker = "profitability_metrics_not_positive"
    else:
        phase = "final_gate_review"
        priority_action = "inspect_remaining_verification_gates"

    safe_to_tune_filters = (
        current_shared >= required_shared
        and gates.get("capture_scope_full_scan_universe") is True
        and gates.get("capture_target_complete") is True
        and gates.get("proof_scan_universe_aligned") is True
        and readiness.get("status") == "ready_for_exact_replay"
        and not replay.get("error")
        and int(replay.get("total_trades") or 0) > 0
    )
    return {
        "phase": phase,
        "priority_action": priority_action,
        "primary_blocker": primary_blocker,
        "blocked_gates": blocked_gates,
        "current_shared_quote_dates": current_shared,
        "required_shared_quote_dates": required_shared,
        "capture_action_status": capture_action.get("status"),
        "capture_next_action": capture_action.get("next_action"),
        "next_scheduled_capture_utc": scheduled_capture.get("scheduled_utc"),
        "next_timed_event": next_timed_event,
        "next_timed_event_kind": (next_timed_event or {}).get("kind"),
        "next_timed_action": (next_timed_event or {}).get("action"),
        "next_timed_event_utc": (next_timed_event or {}).get("scheduled_utc"),
        "next_timed_event_local": (next_timed_event or {}).get("scheduled_local"),
        "next_timed_event_market_local": (next_timed_event or {}).get("scheduled_market_local"),
        "next_timed_event_user_local": (next_timed_event or {}).get("scheduled_user_local"),
        "next_timed_event_calendar": (next_timed_event or {}).get("scan_calendar"),
        "next_timed_event_holiday_calendar_source": (next_timed_event or {}).get("holiday_calendar_source"),
        "next_timed_event_trade_date_is_market_day": (next_timed_event or {}).get(
            "scheduled_trade_date_is_market_day"
        ),
        "next_timed_event_market_timezone": (next_timed_event or {}).get("market_timezone"),
        "next_timed_event_user_timezone": (next_timed_event or {}).get("user_timezone"),
        "diagnostic_ready": diagnostic_ready,
        "diagnostic_replay_next_action": diagnostic_replay.get("next_action"),
        "diagnostic_replay_blockers": diagnostic_blockers,
        "safe_to_tune_filters": safe_to_tune_filters,
        "rationale": rationale,
    }


def build_lane_iteration_plan(report: dict[str, Any]) -> dict[str, Any]:
    proof_window = report.get("proof_window") or {}
    capture = report.get("capture") or {}
    capture_action = report.get("capture_action") or {}
    scheduled_capture = capture_action.get("next_scheduled_capture") or {}
    diagnostic_replay = report.get("diagnostic_replay") or {}
    scan = report.get("scan") or {}
    quote_freshness = scan.get("quote_freshness_context") or {}
    next_fresh_scan = quote_freshness.get("next_fresh_scan") or {}
    fresh_scan_retest_plan = scan.get("fresh_scan_retest_plan") or {}
    verification = report.get("verification_gate") or {}
    lane_next_step = report.get("lane_next_step") or {}
    preserved_evidence_refresh = (
        report.get("preserved_evidence_refresh")
        if isinstance(report.get("preserved_evidence_refresh"), dict)
        else {}
    )
    if not preserved_evidence_refresh:
        derived_refresh = report.get("derived_refresh") if isinstance(report.get("derived_refresh"), dict) else {}
        preserved_evidence_refresh = {
            "stale_after_historical_store_refresh": derived_refresh.get(
                "preserved_evidence_stale_after_historical_store_refresh"
            ),
            "stale_fields": derived_refresh.get("preserved_evidence_stale_fields") or [],
            "command_args": (
                str(derived_refresh.get("preserved_evidence_refresh_command") or "").split()
                if derived_refresh.get("preserved_evidence_refresh_command")
                else None
            ),
            "reason": derived_refresh.get("preserved_evidence_refresh_reason"),
        }

    current_shared = int(proof_window.get("current_shared_quote_dates") or 0)
    required_shared = max(int(proof_window.get("required_shared_quote_dates") or 0), 1)
    diagnostic_required = int(
        proof_window.get("diagnostic_required_shared_quote_dates")
        or diagnostic_replay.get("diagnostic_min_imported_calendar_dates")
        or required_shared
    )
    safe_to_tune = lane_next_step.get("safe_to_tune_filters") is True
    blocked_gates = list(lane_next_step.get("blocked_gates") or [])
    candidate_count = int(scan.get("candidate_count") or 0)
    progress_command = ["python", "scripts/run_ai_commodity_opra_progress.py"]
    steps: list[dict[str, Any]] = []
    fresh_scan_due_now = (
        quote_freshness.get("status") in {"stale_quote_sensitive", "stale_quote_blocked"}
        and next_fresh_scan.get("can_attempt_scan_now") is True
    )

    def _preserved_evidence_refresh_step() -> dict[str, Any]:
        return {
            "step": "preserved_evidence_refresh",
            "status": "due_now",
            "action": "refresh_readiness_replay_after_historical_store_change",
            "reason": preserved_evidence_refresh.get("reason"),
            "stale_fields": list(preserved_evidence_refresh.get("stale_fields") or []),
            "verification_role": "refresh_current_exact_history_evidence",
            "counts_for_verified_profitability": False,
            "actionable_now": True,
            "command": preserved_evidence_refresh.get("command_args")
            or [*progress_command, "--skip-capture", "--skip-scan"],
            "command_cwd": str(ROOT),
            "success_criteria": [
                "readiness_recomputed_against_current_alpaca_opra_dates",
                "replay_recomputed_or_skipped_with_current_shared_depth",
                "preserved_evidence_stale_after_historical_store_refresh_false",
            ],
        }

    if preserved_evidence_refresh.get("stale_after_historical_store_refresh") is True and not fresh_scan_due_now:
        steps.append(_preserved_evidence_refresh_step())

    if candidate_count > 0:
        steps.append(
            {
                "step": "fresh_opra_live_scan",
                "status": "passed",
                "action": "keep_live_scan_candidate_gate_green",
                "verification_role": "live_scan_candidate_gate",
                "counts_for_exact_replay_history": False,
                "candidate_count": candidate_count,
                "actionable_now": False,
                "command": [*progress_command, "--skip-capture"],
                "command_cwd": str(ROOT),
            }
        )
    elif quote_freshness.get("status") in {"stale_quote_sensitive", "stale_quote_blocked"}:
        can_attempt_scan = next_fresh_scan.get("can_attempt_scan_now") is True
        fresh_scan_event_utc = (
            next_fresh_scan.get("reference_utc")
            if can_attempt_scan
            else next_fresh_scan.get("scheduled_utc")
        )
        steps.append(
            {
                "step": "fresh_opra_live_scan",
                "status": "due_now" if can_attempt_scan else "scheduled",
                "action": quote_freshness.get("recommended_action")
                or fresh_scan_retest_plan.get("next_action")
                or "rerun_live_scan_during_fresh_opra_window_before_filter_changes",
                "scheduled_utc": fresh_scan_event_utc or fresh_scan_retest_plan.get("scheduled_utc"),
                "scheduled_local": next_fresh_scan.get("scheduled_local")
                or fresh_scan_retest_plan.get("scheduled_local"),
                "scheduled_market_local": next_fresh_scan.get("scheduled_market_local")
                or fresh_scan_retest_plan.get("scheduled_market_local"),
                "scheduled_user_local": next_fresh_scan.get("scheduled_user_local")
                or fresh_scan_retest_plan.get("scheduled_user_local"),
                "scan_calendar": next_fresh_scan.get("scan_calendar") or fresh_scan_retest_plan.get("scan_calendar"),
                "holiday_calendar_source": next_fresh_scan.get("holiday_calendar_source")
                or fresh_scan_retest_plan.get("holiday_calendar_source"),
                "scheduled_trade_date_is_market_day": next_fresh_scan.get("scheduled_trade_date_is_market_day")
                if next_fresh_scan.get("scheduled_trade_date_is_market_day") is not None
                else fresh_scan_retest_plan.get("scheduled_trade_date_is_market_day"),
                "market_timezone": next_fresh_scan.get("market_timezone")
                or fresh_scan_retest_plan.get("market_timezone"),
                "user_timezone": next_fresh_scan.get("user_timezone")
                or fresh_scan_retest_plan.get("user_timezone"),
                "window_end_utc": next_fresh_scan.get("window_end_utc")
                or fresh_scan_retest_plan.get("window_end_utc"),
                "window_end_market_local": next_fresh_scan.get("window_end_market_local")
                or fresh_scan_retest_plan.get("window_end_market_local"),
                "window_end_user_local": next_fresh_scan.get("window_end_user_local")
                or fresh_scan_retest_plan.get("window_end_user_local"),
                "timing_status": next_fresh_scan.get("status"),
                "can_attempt_now": can_attempt_scan,
                "actionable_now": can_attempt_scan,
                "not_before_utc": next_fresh_scan.get("scheduled_utc") or fresh_scan_retest_plan.get("scheduled_utc"),
                "not_before_user_local": next_fresh_scan.get("scheduled_user_local")
                or fresh_scan_retest_plan.get("scheduled_user_local"),
                "verification_role": "live_scan_candidate_gate",
                "counts_for_exact_replay_history": False,
                "primary_probe_symbol": fresh_scan_retest_plan.get("primary_probe_symbol"),
                "command": [*progress_command, "--skip-capture"],
                "command_cwd": str(ROOT),
                "success_criteria": fresh_scan_retest_plan.get("success_criteria")
                or ["fresh_scan_candidate_count_above_zero"],
            }
        )

    if preserved_evidence_refresh.get("stale_after_historical_store_refresh") is True and fresh_scan_due_now:
        steps.append(_preserved_evidence_refresh_step())

    if current_shared < required_shared:
        capture_due_now = capture_action.get("can_attempt_capture_now") is True
        target_trade_date = capture_action.get("next_missing_capture_trade_date") or proof_window.get(
            "next_missing_capture_trade_date"
        )
        capture_command = [*progress_command, "--force-capture"]
        if target_trade_date:
            capture_command.extend(["--target-date", str(target_trade_date)])
        capture_status = "due_now" if capture_due_now else "scheduled"
        if not scheduled_capture.get("scheduled_utc") and not capture_due_now:
            capture_status = capture_action.get("status") or "pending"
        steps.append(
            {
                "step": "post_close_full_universe_capture",
                "status": capture_status,
                "action": capture_action.get("next_action") or "continue_daily_full_universe_capture_loop",
                "scheduled_utc": scheduled_capture.get("scheduled_utc"),
                "scheduled_local": scheduled_capture.get("scheduled_local"),
                "scheduled_user_local": scheduled_capture.get("scheduled_local"),
                "timing_status": scheduled_capture.get("timing_status"),
                "target_trade_date": target_trade_date,
                "expected_scope": capture.get("scope") or "ai_commodity_scan_universe",
                "expected_symbol_count": capture.get("symbol_count"),
                "verification_role": "exact_opra_history_accumulation",
                "counts_for_exact_replay_history": True,
                "actionable_now": capture_due_now,
                "not_before_utc": scheduled_capture.get("scheduled_utc"),
                "not_before_user_local": scheduled_capture.get("scheduled_local"),
                "premature_run_guard": "target_date_capturable_guard",
                "command": capture_command,
                "command_cwd": str(ROOT),
                "success_criteria": [
                    "capture_target_complete_true",
                    "shared_quote_dates_increase_or_target_was_already_complete",
                    "full_universe_hard_gates_remain_true",
                ],
            }
        )
    else:
        steps.append(
            {
                "step": "post_close_full_universe_capture",
                "status": "passed",
                "action": "maintain_daily_capture_loop_for_forward_monitoring",
                "verification_role": "exact_opra_history_accumulation",
                "counts_for_exact_replay_history": True,
                "actionable_now": False,
                "command": [*progress_command],
                "command_cwd": str(ROOT),
            }
        )

    if current_shared < diagnostic_required:
        steps.append(
            {
                "step": "diagnostic_replay_checkpoint",
                "status": "blocked_until_shared_quote_dates",
                "action": "accumulate_replay_simulation_shared_opra_dates",
                "current_shared_quote_dates": current_shared,
                "required_shared_quote_dates": diagnostic_required,
                "remaining_shared_quote_dates": max(diagnostic_required - current_shared, 0),
                "verification_role": "early_signal_only_not_full_verification",
                "counts_for_verified_profitability": False,
                "actionable_now": False,
                "command": [*progress_command],
                "command_cwd": str(ROOT),
            }
        )
    else:
        steps.append(
            {
                "step": "diagnostic_replay_checkpoint",
                "status": "due_now",
                "action": diagnostic_replay.get("next_action") or "run_diagnostic_exact_opra_replay_checkpoint",
                "current_shared_quote_dates": current_shared,
                "required_shared_quote_dates": diagnostic_required,
                "verification_role": "early_signal_only_not_full_verification",
                "counts_for_verified_profitability": False,
                "actionable_now": True,
                "command": [*progress_command],
                "command_cwd": str(ROOT),
            }
        )

    if current_shared < required_shared:
        steps.append(
            {
                "step": "full_exact_replay_profitability_gate",
                "status": "blocked_until_shared_quote_dates",
                "action": "accumulate_full_exact_alpaca_opra_history",
                "current_shared_quote_dates": current_shared,
                "required_shared_quote_dates": required_shared,
                "remaining_shared_quote_dates": max(required_shared - current_shared, 0),
                "verification_role": "verified_profitability_gate",
                "actionable_now": False,
                "command": [*progress_command],
                "command_cwd": str(ROOT),
            }
        )
    else:
        steps.append(
            {
                "step": "full_exact_replay_profitability_gate",
                "status": "due_now",
                "action": "run_exact_alpaca_opra_replay_and_profitability_gate",
                "current_shared_quote_dates": current_shared,
                "required_shared_quote_dates": required_shared,
                "verification_role": "verified_profitability_gate",
                "actionable_now": True,
                "command": [*progress_command],
                "command_cwd": str(ROOT),
            }
        )

    steps.append(
        {
            "step": "filter_tuning",
            "status": "unlocked" if safe_to_tune else "locked",
            "action": "tune_lane_using_exact_opra_replay_metrics" if safe_to_tune else "hold_filters_until_exact_replay_is_ready",
            "locked_by": [] if safe_to_tune else blocked_gates,
            "verification_role": "profitability_iteration_after_exact_evidence",
            "actionable_now": safe_to_tune,
        }
    )

    return {
        "status": "verified" if verification.get("verified") is True else "active",
        "current_phase": lane_next_step.get("phase"),
        "priority_action": lane_next_step.get("priority_action"),
        "safe_to_tune_filters": safe_to_tune,
        "current_shared_quote_dates": current_shared,
        "required_shared_quote_dates": required_shared,
        "diagnostic_required_shared_quote_dates": diagnostic_required,
        "steps": steps,
    }


def _command_display(command: Any) -> str | None:
    if isinstance(command, list):
        parts = [str(part) for part in command if str(part)]
        return " ".join(parts) if parts else None
    if command:
        return str(command)
    return None


def _next_execution_runbook_card(
    next_execution: dict[str, Any],
    *,
    recommended_action: str,
    clock_status: str | None,
    wait_minutes: float | None,
    window_minutes_remaining: float | None,
) -> dict[str, Any]:
    command_display = _command_display(next_execution.get("command"))
    if recommended_action == "run_next_execution_command":
        guard_status = "ready_to_run_guarded_command"
        summary = "run_the_guarded_next_execution_command"
    elif recommended_action == "wait_until_not_before":
        guard_status = "clock_guard_active"
        summary = "wait_until_the_not_before_time_then_rerun_the_probe_or_command"
    elif recommended_action == "run_progress_report":
        guard_status = "fresh_scan_window_expired"
        summary = "rerun_the_progress_report_before_using_a_stale_command"
    elif recommended_action == "no_action_verified":
        guard_status = "goal_verified"
        summary = "no_lane_iteration_action_required"
    else:
        guard_status = "manual_review"
        summary = "inspect_next_execution_blockers_before_running_any_command"
    not_before_user_local = next_execution.get("not_before_user_local") or _utc_iso_in_timezone(
        next_execution.get("not_before_utc")
    )
    window_end_user_local = next_execution.get("window_end_user_local") or _utc_iso_in_timezone(
        next_execution.get("window_end_utc")
    )
    return {
        "summary": summary,
        "guard_status": guard_status,
        "clock_status": clock_status,
        "selected_step": next_execution.get("selected_step"),
        "selected_step_status": next_execution.get("selected_step_status"),
        "recommended_action": recommended_action,
        "run_next_execution_command": recommended_action == "run_next_execution_command",
        "command": command_display,
        "command_args": next_execution.get("command"),
        "command_cwd": next_execution.get("command_cwd"),
        "not_before_utc": next_execution.get("not_before_utc"),
        "not_before_user_local": not_before_user_local,
        "window_end_utc": next_execution.get("window_end_utc"),
        "window_end_user_local": window_end_user_local,
        "runbook_timezone": next_execution.get("runbook_timezone") or _runbook_timezone_name(),
        "wait_minutes": wait_minutes,
        "window_minutes_remaining": window_minutes_remaining,
        "premature_run_guard": next_execution.get("premature_run_guard"),
        "blockers": list(next_execution.get("blockers") or []),
        "success_criteria": list(next_execution.get("success_criteria") or []),
    }


def build_run_next_execution_guard_summary(
    *,
    next_execution: dict[str, Any] | None = None,
    runbook_card: dict[str, Any] | None = None,
    runbook_snapshot: dict[str, Any] | None = None,
    preflight: dict[str, Any] | None = None,
    run_next_execution_command: bool | None = None,
    run_next_execution_command_reason: str | None = None,
    run_next_execution_command_required_action: str | None = None,
    run_next_execution_command_blockers: list[str] | None = None,
    command: Any = None,
) -> dict[str, Any]:
    next_execution = next_execution or {}
    runbook_card = runbook_card or {}
    runbook_snapshot = runbook_snapshot or {}
    preflight = preflight or {}
    can_run = (
        run_next_execution_command
        if run_next_execution_command is not None
        else runbook_card.get("run_next_execution_command") is True
    )
    command_value = command
    if command_value is None:
        command_value = (
            runbook_card.get("command_args")
            or next_execution.get("command")
            or next_execution.get("command_display")
            or runbook_card.get("command")
        )
    command_display = _command_display(command_value) or _command_display(runbook_card.get("command"))
    raw_blockers = (
        run_next_execution_command_blockers
        if run_next_execution_command_blockers is not None
        else runbook_card.get("blockers") or next_execution.get("blockers") or []
    )
    blockers = [str(item) for item in raw_blockers]
    recommended_action = (
        run_next_execution_command_required_action
        or runbook_card.get("recommended_action")
        or runbook_snapshot.get("recommended_action")
    )
    if not recommended_action and next_execution.get("status") == "waiting_until_not_before":
        recommended_action = "wait_until_not_before"
    not_before_utc = runbook_card.get("not_before_utc") or next_execution.get("not_before_utc")
    not_before_user_local = (
        runbook_card.get("not_before_user_local")
        or next_execution.get("not_before_user_local")
        or _utc_iso_in_timezone(not_before_utc)
    )
    window_end_utc = runbook_card.get("window_end_utc") or next_execution.get("window_end_utc")
    window_end_user_local = (
        runbook_card.get("window_end_user_local")
        or next_execution.get("window_end_user_local")
        or _utc_iso_in_timezone(window_end_utc)
    )
    if run_next_execution_command_reason is not None:
        reason = run_next_execution_command_reason
    elif can_run:
        reason = "ready_to_run_guarded_command"
    elif recommended_action == "wait_until_not_before":
        fallback_not_before = not_before_user_local or not_before_utc
        if not fallback_not_before:
            waiting_blockers = [item for item in blockers if item.startswith("waiting_until_not_before:")]
            fallback_not_before = waiting_blockers[0].split(":", 1)[1] if waiting_blockers else "unknown"
        reason = f"waiting_until_not_before:{fallback_not_before}"
    elif recommended_action == "run_progress_report":
        reason = "fresh_scan_window_expired_rerun_progress_report"
    elif recommended_action == "no_action_verified":
        reason = "verification_already_complete"
    elif not command_display:
        reason = "missing_next_execution_command"
    elif blockers:
        reason = "blocked_by_next_execution_contract"
    else:
        reason = f"recommended_action:{recommended_action or 'inspect_next_execution_blockers'}"
    if can_run:
        status = "ready_to_run_guarded_command"
        required_action = None
        blockers_for_summary: list[str] = []
        allowed_command_now = command_display
    elif recommended_action == "wait_until_not_before":
        status = "waiting_until_not_before"
        required_action = recommended_action
        blockers_for_summary = blockers
        allowed_command_now = None
    elif recommended_action == "run_progress_report":
        status = "progress_report_refresh_required"
        required_action = recommended_action
        blockers_for_summary = blockers
        allowed_command_now = None
    elif recommended_action == "no_action_verified":
        status = "verified_no_action_required"
        required_action = recommended_action
        blockers_for_summary = blockers
        allowed_command_now = None
    elif blockers:
        status = "blocked_by_next_execution_contract"
        required_action = recommended_action or "inspect_next_execution_blockers"
        blockers_for_summary = blockers
        allowed_command_now = None
    else:
        status = "manual_review_required"
        required_action = recommended_action or "inspect_next_execution_blockers"
        blockers_for_summary = blockers
        allowed_command_now = None
    wait_minutes = (
        runbook_card.get("wait_minutes")
        if runbook_card.get("wait_minutes") is not None
        else runbook_snapshot.get("wait_minutes")
    )
    window_minutes_remaining = (
        runbook_card.get("window_minutes_remaining")
        if runbook_card.get("window_minutes_remaining") is not None
        else runbook_snapshot.get("window_minutes_remaining")
    )
    return {
        "status": status,
        "run_next_execution_command": bool(can_run),
        "reason": reason,
        "required_action": required_action,
        "guard_status": runbook_card.get("guard_status"),
        "clock_status": runbook_card.get("clock_status") or runbook_snapshot.get("clock_status"),
        "selected_step": runbook_card.get("selected_step") or next_execution.get("selected_step"),
        "selected_step_status": runbook_card.get("selected_step_status")
        or next_execution.get("selected_step_status"),
        "wait_minutes": wait_minutes,
        "window_minutes_remaining": window_minutes_remaining,
        "not_before_utc": not_before_utc,
        "not_before_user_local": not_before_user_local,
        "window_end_utc": window_end_utc,
        "window_end_user_local": window_end_user_local,
        "command": command_display,
        "allowed_command_now": allowed_command_now,
        "guarded_command_to_run_when_allowed": (
            command_display if not can_run and recommended_action == "wait_until_not_before" else None
        ),
        "blockers": blockers_for_summary,
        "preflight_status": preflight.get("status"),
        "preflight_failed_checks": list(preflight.get("failed_checks") or []),
        "preflight_non_clock_blockers": list(preflight.get("non_clock_blockers") or []),
    }


def _forward_capture_queue_summary_items(queue: Any, *, limit: int = 5) -> list[dict[str, Any]]:
    items: list[dict[str, Any]] = []
    if not isinstance(queue, list):
        return items
    for index, item in enumerate(queue[: max(int(limit), 0)], start=1):
        if not isinstance(item, dict):
            continue
        items.append(
            {
                "rank": index,
                "trade_date": item.get("trade_date"),
                "not_before_user_local": item.get("not_before_user_local"),
                "not_before_utc": item.get("not_before_utc"),
                "expected_shared_quote_dates_after_capture": item.get(
                    "expected_shared_quote_dates_after_capture"
                ),
                "diagnostic_replay_unlocked_after_capture": item.get(
                    "diagnostic_replay_unlocked_after_capture"
                ),
                "full_exact_replay_unlocked_after_capture": item.get(
                    "full_exact_replay_unlocked_after_capture"
                ),
                "command": item.get("command"),
            }
        )
    return items


def _forward_capture_queue_markdown_lines(queue: Any) -> list[str]:
    lines: list[str] = []
    for item in _forward_capture_queue_summary_items(queue):
        lines.append(
            f"- {item.get('rank')}. `{item.get('trade_date')}` not before "
            f"`{item.get('not_before_user_local')}` expected shared dates "
            f"`{item.get('expected_shared_quote_dates_after_capture')}` diagnostic unlock "
            f"`{item.get('diagnostic_replay_unlocked_after_capture')}` full unlock "
            f"`{item.get('full_exact_replay_unlocked_after_capture')}` command `{item.get('command')}`"
        )
    return lines


def build_next_execution_contract(report: dict[str, Any]) -> dict[str, Any]:
    lane_next_step = report.get("lane_next_step") or {}
    next_timed_event = (
        lane_next_step.get("next_timed_event")
        if isinstance(lane_next_step.get("next_timed_event"), dict)
        else {}
    )
    iteration_plan = report.get("lane_iteration_plan") or {}
    automation = report.get("automation_health") or {}
    steps = [step for step in (iteration_plan.get("steps") or []) if isinstance(step, dict)]
    reference_now = _parse_utc_datetime(report.get("generated_at")) or _utc_now()
    event_kind = next_timed_event.get("kind")
    expected_step_by_event = {
        "fresh_opra_scan": "fresh_opra_live_scan",
        "post_close_opra_capture": "post_close_full_universe_capture",
    }
    expected_step = expected_step_by_event.get(str(event_kind or ""))
    event_utc = next_timed_event.get("scheduled_utc")
    fresh_scan_due_now = event_kind == "fresh_opra_scan" and next_timed_event.get("can_attempt_now") is True

    selected_step: dict[str, Any] | None = None
    if not fresh_scan_due_now:
        selected_step = next(
            (
                step
                for step in steps
                if step.get("step") == "preserved_evidence_refresh"
                and step.get("status") == "due_now"
            ),
            None,
        )
    if selected_step is None and expected_step:
        for step in steps:
            if step.get("step") == expected_step:
                selected_step = step
                break
    if selected_step is None and event_utc:
        for step in steps:
            if step.get("scheduled_utc") == event_utc:
                selected_step = step
                break
    if selected_step is None:
        selected_step = next(
            (
                step
                for step in steps
                if step.get("status") in {"due_now", "scheduled"}
                and step.get("step") != "filter_tuning"
            ),
            None,
        )

    blockers: list[str] = []
    if automation.get("healthy") is not True:
        blockers.append(f"automation:{automation.get('blocker') or automation.get('status')}")
    if selected_step is None:
        blockers.append("no_next_iteration_step")

    selected_scheduled_utc = selected_step.get("scheduled_utc") if selected_step else None
    matches_next_timed_event = bool(
        selected_step
        and event_utc
        and selected_scheduled_utc == event_utc
    )
    if (
        event_utc
        and selected_step
        and selected_step.get("step") != "preserved_evidence_refresh"
        and not matches_next_timed_event
    ):
        blockers.append(f"step_event_mismatch:{selected_step.get('step')}:{selected_scheduled_utc}:{event_utc}")

    actionable_now = selected_step.get("actionable_now") is True if selected_step else False
    not_before_utc = selected_step.get("not_before_utc") if selected_step else None
    not_before_dt = _parse_utc_datetime(not_before_utc)
    if selected_step and not actionable_now and not_before_dt is not None and reference_now < not_before_dt:
        blockers.append(f"waiting_until_not_before:{not_before_utc}")
    elif selected_step and not actionable_now and str(selected_step.get("status") or "").startswith("blocked_"):
        blockers.append(f"step_blocked:{selected_step.get('status')}")
    elif selected_step and not actionable_now and selected_step.get("status") == "locked":
        blockers.append("step_locked")

    if blockers:
        if any(str(item).startswith("waiting_until_not_before:") for item in blockers) and len(blockers) == 1:
            status = "waiting_until_not_before"
        elif any(str(item).startswith("waiting_until_not_before:") for item in blockers) and automation.get("healthy") is True:
            status = "waiting_until_not_before"
        else:
            status = "blocked"
    elif actionable_now:
        status = "ready_to_run"
    else:
        status = "not_actionable"

    command = selected_step.get("command") if selected_step else None
    selected_window_end_utc = selected_step.get("window_end_utc") if selected_step else None
    selected_not_before_user_local = (
        selected_step.get("not_before_user_local") if selected_step else None
    ) or _utc_iso_in_timezone(not_before_utc)
    selected_scheduled_user_local = (
        selected_step.get("scheduled_user_local") if selected_step else None
    ) or _utc_iso_in_timezone(selected_scheduled_utc)
    selected_window_end_user_local = (
        selected_step.get("window_end_user_local") if selected_step else None
    ) or _utc_iso_in_timezone(selected_window_end_utc)
    return {
        "status": status,
        "reference_utc": _utc_iso(reference_now),
        "automation_healthy": automation.get("healthy") is True,
        "next_timed_event_kind": event_kind,
        "next_timed_event_utc": event_utc,
        "next_timed_event_user_local": next_timed_event.get("scheduled_user_local"),
        "selected_step": selected_step.get("step") if selected_step else None,
        "selected_step_status": selected_step.get("status") if selected_step else None,
        "matches_next_timed_event": matches_next_timed_event,
        "action": selected_step.get("action") if selected_step else None,
        "actionable_now": actionable_now,
        "not_before_utc": not_before_utc,
        "not_before_user_local": selected_not_before_user_local,
        "scheduled_utc": selected_scheduled_utc,
        "scheduled_user_local": selected_scheduled_user_local,
        "window_end_utc": selected_window_end_utc,
        "window_end_user_local": selected_window_end_user_local,
        "runbook_timezone": _runbook_timezone_name(),
        "command": command,
        "command_display": _command_display(command),
        "command_cwd": selected_step.get("command_cwd") if selected_step else None,
        "premature_run_guard": selected_step.get("premature_run_guard") if selected_step else None,
        "success_criteria": selected_step.get("success_criteria") if selected_step else None,
        "blockers": blockers,
    }


def build_next_execution_preflight(
    report: dict[str, Any],
    *,
    reference_now: datetime | None = None,
) -> dict[str, Any]:
    next_execution = (
        report.get("next_execution_contract")
        if isinstance(report.get("next_execution_contract"), dict)
        else build_next_execution_contract(report)
    )
    automation = report.get("automation_health") if isinstance(report.get("automation_health"), dict) else {}
    proof_window = report.get("proof_window") if isinstance(report.get("proof_window"), dict) else {}
    proof_source_audit = report.get("proof_source_audit") if isinstance(report.get("proof_source_audit"), dict) else {}
    verification = report.get("verification_gate") if isinstance(report.get("verification_gate"), dict) else {}
    gates = verification.get("gates") if isinstance(verification.get("gates"), dict) else {}
    proof_source_isolation = (
        report.get("proof_source_isolation_contract")
        if isinstance(report.get("proof_source_isolation_contract"), dict)
        else build_proof_source_isolation_contract(report)
    )
    exact_history_plan = (
        report.get("exact_history_acquisition_plan")
        if isinstance(report.get("exact_history_acquisition_plan"), dict)
        else {}
    )
    capture_continuity_contract = (
        exact_history_plan.get("capture_continuity_contract")
        if isinstance(exact_history_plan.get("capture_continuity_contract"), dict)
        else {}
    )
    reference = reference_now or _parse_utc_datetime(report.get("generated_at")) or _utc_now()
    if reference.tzinfo is None:
        reference = reference.replace(tzinfo=UTC)
    reference = reference.astimezone(UTC)
    not_before_utc = next_execution.get("not_before_utc")
    not_before_dt = _parse_utc_datetime(not_before_utc)
    window_end_utc = next_execution.get("window_end_utc")
    window_end_dt = _parse_utc_datetime(window_end_utc)
    command_args_raw = next_execution.get("command")
    if isinstance(command_args_raw, list):
        command_args = [str(item) for item in command_args_raw]
    elif command_args_raw:
        command_args = str(command_args_raw).split()
    else:
        command_args = []
    command_display = (
        next_execution.get("command_display")
        or _command_display(next_execution.get("command"))
        or ""
    )
    command_display_parts = command_display.split()
    blockers = [str(item) for item in next_execution.get("blockers") or []]
    clock_blockers = [item for item in blockers if item.startswith("waiting_until_not_before:")]
    non_clock_blockers = [item for item in blockers if not item.startswith("waiting_until_not_before:")]
    due_by_clock = bool(not_before_dt is not None and reference >= not_before_dt)
    expired_by_clock = bool(window_end_dt is not None and reference >= window_end_dt)
    provider_ok = report.get("provider") == "alpaca:sip:opra"
    alpaca_enabled_ok = report.get("alpaca_enabled") is True or provider_ok
    proof_source_ok = (
        report.get("proof_source_label")
        or proof_window.get("source_label")
        or proof_source_audit.get("proof_source_label")
    ) == ALPACA_OPRA_SOURCE_LABEL
    command_present = bool(command_display and next_execution.get("command"))
    selected_step_name = str(next_execution.get("selected_step") or "")
    selected_step_present = bool(selected_step_name)
    proof_source_isolation_required = selected_step_present
    proof_source_isolation_status = proof_source_isolation.get("status")
    proof_source_isolation_blockers = list(proof_source_isolation.get("blockers") or [])
    capture_continuity_required = selected_step_name == "post_close_full_universe_capture"
    full_universe_hard_gates_required = selected_step_name == "post_close_full_universe_capture"
    capture_command_contract_required = selected_step_name == "post_close_full_universe_capture"
    expected_capture_target_date = (
        exact_history_plan.get("next_capture_trade_date")
        or proof_window.get("next_missing_capture_trade_date")
        or proof_window.get("next_target_trade_date")
        or proof_window.get("current_target_trade_date")
    )
    command_target_date = None
    if "--target-date" in command_args:
        target_index = command_args.index("--target-date")
        if target_index + 1 < len(command_args):
            command_target_date = command_args[target_index + 1]
    elif "--target-date" in command_display_parts:
        target_index = command_display_parts.index("--target-date")
        if target_index + 1 < len(command_display_parts):
            command_target_date = command_display_parts[target_index + 1]
    command_uses_force_capture = "--force-capture" in command_args or "--force-capture" in command_display_parts
    target_date_guard = next_execution.get("premature_run_guard")
    capture_scope_full_scan_universe = gates.get("capture_scope_full_scan_universe")
    proof_scan_universe_aligned = gates.get("proof_scan_universe_aligned")
    proof_window_has_missed_capture_dates = "missed_capture_trade_dates_since_latest_shared" in proof_window
    missed_capture_trade_dates_raw = (
        capture_continuity_contract.get("missed_capture_trade_dates")
        if capture_continuity_contract
        else proof_window.get("missed_capture_trade_dates_since_latest_shared")
        if proof_window_has_missed_capture_dates
        else []
    )
    missed_capture_trade_dates = list(missed_capture_trade_dates_raw or [])
    capture_continuity_status = capture_continuity_contract.get("status")
    if not capture_continuity_status and proof_window_has_missed_capture_dates:
        capture_continuity_status = (
            "intervention_required_missed_capture_dates"
            if missed_capture_trade_dates
            else "on_track_no_missed_capture_dates"
        )
    missed_capture_policy = capture_continuity_contract.get("missed_capture_policy")
    if not missed_capture_policy and (capture_continuity_contract or proof_window_has_missed_capture_dates):
        missed_capture_policy = MISSED_OPRA_BBO_CAPTURE_POLICY
    missed_capture_dates_recoverable = capture_continuity_contract.get("missed_capture_dates_recoverable")
    if missed_capture_dates_recoverable is None and missed_capture_trade_dates:
        missed_capture_dates_recoverable = False
    automation_healthy = automation.get("healthy") is True
    clock_only_blocked = bool(clock_blockers) and not non_clock_blockers
    checks = [
        _check_result("provider_is_alpaca_sip_opra", provider_ok, actual=report.get("provider"), expected="alpaca:sip:opra"),
        _check_result("alpaca_enabled", alpaca_enabled_ok, actual=report.get("alpaca_enabled"), expected=True),
        _check_result(
            "proof_source_is_alpaca_opra_daily_snapshot",
            proof_source_ok,
            actual=report.get("proof_source_label") or proof_window.get("source_label") or proof_source_audit.get("proof_source_label"),
            expected=ALPACA_OPRA_SOURCE_LABEL,
        ),
        _check_result("automation_healthy", automation_healthy, actual=automation.get("healthy"), expected=True),
        _check_result("selected_step_present", selected_step_present, actual=next_execution.get("selected_step"), expected="nonempty"),
        _check_result("command_present", command_present, actual=command_display, expected="nonempty"),
        _check_result("no_non_clock_blockers", not non_clock_blockers, actual=non_clock_blockers, expected=[]),
        _check_result("not_expired_by_clock", not expired_by_clock, actual=window_end_utc, expected="future_or_missing"),
    ]
    if proof_source_isolation_required:
        checks.extend(
            [
                _check_result(
                    "proof_source_isolation_contract_present",
                    bool(proof_source_isolation),
                    actual=bool(proof_source_isolation),
                    expected=True,
                ),
                _check_result(
                    "proof_source_isolation_contract_clean",
                    proof_source_isolation_status == "isolated_to_alpaca_opra_proof_source"
                    and not proof_source_isolation_blockers,
                    actual={
                        "status": proof_source_isolation_status,
                        "blockers": proof_source_isolation_blockers,
                    },
                    expected="isolated_to_alpaca_opra_proof_source with no blockers",
                ),
            ]
        )
    if capture_continuity_required:
        checks.extend(
            [
                _check_result(
                    "capture_continuity_evidence_present",
                    bool(capture_continuity_contract) or proof_window_has_missed_capture_dates,
                    actual={
                        "has_contract": bool(capture_continuity_contract),
                        "proof_window_has_missed_capture_dates": proof_window_has_missed_capture_dates,
                    },
                    expected="capture_continuity_contract or proof_window.missed_capture_trade_dates_since_latest_shared",
                ),
                _check_result(
                    "capture_continuity_status_on_track_or_complete",
                    capture_continuity_status in CAPTURE_CONTINUITY_OK_STATUSES,
                    actual=capture_continuity_status,
                    expected=list(CAPTURE_CONTINUITY_OK_STATUSES),
                ),
                _check_result(
                    "capture_continuity_has_no_missed_dates",
                    not missed_capture_trade_dates,
                    actual=missed_capture_trade_dates,
                    expected=[],
                ),
                _check_result(
                    "capture_continuity_policy_locked",
                    missed_capture_policy == MISSED_OPRA_BBO_CAPTURE_POLICY,
                    actual=missed_capture_policy,
                    expected=MISSED_OPRA_BBO_CAPTURE_POLICY,
                ),
                _check_result(
                    "capture_continuity_does_not_claim_missed_dates_recoverable",
                    missed_capture_dates_recoverable is not True,
                    actual=missed_capture_dates_recoverable,
                    expected="not true",
                ),
            ]
        )
    if full_universe_hard_gates_required:
        checks.extend(
            [
                _check_result(
                    "capture_scope_full_scan_universe",
                    capture_scope_full_scan_universe is True,
                    actual=capture_scope_full_scan_universe,
                    expected=True,
                ),
                _check_result(
                    "proof_scan_universe_aligned",
                    proof_scan_universe_aligned is True,
                    actual=proof_scan_universe_aligned,
                    expected=True,
                ),
            ]
        )
    if capture_command_contract_required:
        checks.extend(
            [
                _check_result(
                    "target_date_capturable_guard_preserved",
                    target_date_guard == "target_date_capturable_guard",
                    actual=target_date_guard,
                    expected="target_date_capturable_guard",
                ),
                _check_result(
                    "capture_command_uses_force_capture",
                    command_uses_force_capture,
                    actual=command_args or command_display,
                    expected="--force-capture",
                ),
                _check_result(
                    "capture_command_target_date_present",
                    bool(command_target_date),
                    actual=command_target_date,
                    expected="nonempty --target-date",
                ),
                _check_result(
                    "capture_command_target_date_matches_next_capture",
                    bool(command_target_date)
                    and bool(expected_capture_target_date)
                    and command_target_date == str(expected_capture_target_date),
                    actual={
                        "command_target_date": command_target_date,
                        "expected_capture_target_date": expected_capture_target_date,
                    },
                    expected="command --target-date equals exact_history_acquisition_plan.next_capture_trade_date",
                ),
            ]
        )
    failed_checks = [item["name"] for item in checks if not item.get("passed")]
    if expired_by_clock:
        status = "expired_by_clock"
        next_action = "rerun_progress_report_before_command"
    elif failed_checks:
        status = "blocked"
        next_action = "resolve_preflight_blockers_before_command"
    elif clock_only_blocked and not due_by_clock:
        status = "ready_after_clock"
        next_action = "wait_until_not_before_then_run_next_execution_command"
    elif not blockers or (clock_only_blocked and due_by_clock):
        status = "ready_now"
        next_action = "run_next_execution_command"
    else:
        status = "blocked"
        next_action = "inspect_next_execution_blockers"
    return {
        "status": status,
        "reference_utc": _utc_iso(reference),
        "selected_step": next_execution.get("selected_step"),
        "command": command_display,
        "command_args": next_execution.get("command"),
        "command_cwd": next_execution.get("command_cwd"),
        "not_before_utc": not_before_utc,
        "not_before_user_local": next_execution.get("not_before_user_local") or _utc_iso_in_timezone(not_before_utc),
        "window_end_utc": window_end_utc,
        "window_end_user_local": next_execution.get("window_end_user_local") or _utc_iso_in_timezone(window_end_utc),
        "due_by_clock": due_by_clock,
        "expired_by_clock": expired_by_clock,
        "clock_only_blocked": clock_only_blocked,
        "proof_source_isolation_required": proof_source_isolation_required,
        "proof_source_isolation_status": proof_source_isolation_status,
        "proof_source_isolation_blockers": proof_source_isolation_blockers,
        "capture_continuity_required": capture_continuity_required,
        "capture_continuity_status": capture_continuity_status,
        "capture_continuity_missed_capture_trade_dates": missed_capture_trade_dates,
        "capture_continuity_missed_capture_policy": missed_capture_policy,
        "capture_continuity_missed_capture_dates_recoverable": missed_capture_dates_recoverable,
        "full_universe_hard_gates_required": full_universe_hard_gates_required,
        "capture_scope_full_scan_universe": capture_scope_full_scan_universe,
        "proof_scan_universe_aligned": proof_scan_universe_aligned,
        "capture_command_contract_required": capture_command_contract_required,
        "target_date_capturable_guard": target_date_guard,
        "capture_command_uses_force_capture": command_uses_force_capture,
        "capture_command_target_date": command_target_date,
        "expected_capture_target_date": expected_capture_target_date,
        "blockers": blockers,
        "non_clock_blockers": non_clock_blockers,
        "failed_checks": failed_checks,
        "checks": checks,
        "next_action": next_action,
    }


def _int_from_nested(payload: dict[str, Any], *keys: str) -> int:
    value: Any = payload
    for key in keys:
        if not isinstance(value, dict):
            return 0
        value = value.get(key)
    try:
        return int(value or 0)
    except (TypeError, ValueError):
        return 0


def _check_result(name: str, passed: bool, *, actual: Any = None, expected: Any = None) -> dict[str, Any]:
    return {
        "name": name,
        "passed": bool(passed),
        "actual": actual,
        "expected": expected,
    }


def _previous_runbook_review_fields(
    previous_contract: dict[str, Any],
    previous_report: dict[str, Any],
    *,
    current_ref: datetime | None = None,
    not_before_dt: datetime | None = None,
) -> dict[str, Any]:
    runbook_card = previous_report.get("next_execution_runbook_card")
    if not isinstance(runbook_card, dict) or not runbook_card:
        return {
            "previous_runbook_card": None,
            "previous_runbook_guard_status": None,
            "previous_runbook_recommended_action": None,
            "previous_runbook_command": None,
            "previous_runbook_not_before_user_local": None,
            "previous_runbook_window_end_user_local": None,
            "previous_runbook_success_criteria": None,
            "previous_runbook_command_matches_contract": False,
            "ran_from_runbook_card": False,
            "ran_from_runbook_card_inference": "no_previous_runbook_card",
        }

    contract_command = previous_contract.get("command_display") or _command_display(previous_contract.get("command"))
    runbook_command = runbook_card.get("command") or _command_display(runbook_card.get("command_args"))
    command_matches = bool(contract_command and runbook_command and contract_command == runbook_command)
    due_window_reached = current_ref is not None and (not_before_dt is None or current_ref >= not_before_dt)
    ran_from_runbook_card = bool(command_matches and due_window_reached)
    if ran_from_runbook_card:
        inference = "previous_runbook_command_matches_contract_and_due_window_reached"
    elif not due_window_reached:
        inference = "previous_runbook_card_waiting_until_not_before"
    elif not command_matches:
        inference = "previous_runbook_command_differs_from_contract"
    else:
        inference = "previous_runbook_card_not_executable"

    return {
        "previous_runbook_card": dict(runbook_card),
        "previous_runbook_guard_status": runbook_card.get("guard_status"),
        "previous_runbook_recommended_action": runbook_card.get("recommended_action"),
        "previous_runbook_command": runbook_command,
        "previous_runbook_not_before_user_local": runbook_card.get("not_before_user_local"),
        "previous_runbook_window_end_user_local": runbook_card.get("window_end_user_local"),
        "previous_runbook_success_criteria": runbook_card.get("success_criteria"),
        "previous_runbook_command_matches_contract": command_matches,
        "ran_from_runbook_card": ran_from_runbook_card,
        "ran_from_runbook_card_inference": inference,
    }


def build_last_execution_review(
    previous_report: dict[str, Any] | None,
    current_report: dict[str, Any],
) -> dict[str, Any]:
    previous = previous_report if isinstance(previous_report, dict) else {}
    previous_contract = previous.get("next_execution_contract") if isinstance(previous.get("next_execution_contract"), dict) else {}
    if not previous_contract:
        return {
            "status": "no_previous_execution_contract",
            "evaluated_at_utc": current_report.get("generated_at"),
        }

    selected_step = previous_contract.get("selected_step")
    current_ref = _parse_utc_datetime(current_report.get("generated_at")) or _utc_now()
    not_before = previous_contract.get("not_before_utc")
    not_before_dt = _parse_utc_datetime(not_before)
    previous_runbook_fields = _previous_runbook_review_fields(
        previous_contract,
        previous,
        current_ref=current_ref,
        not_before_dt=not_before_dt,
    )
    if not_before_dt is not None and current_ref < not_before_dt:
        return {
            "status": "not_due_yet",
            "evaluated_at_utc": _utc_iso(current_ref),
            "previous_selected_step": selected_step,
            "previous_status": previous_contract.get("status"),
            "not_before_utc": not_before,
            "command": previous_contract.get("command"),
            "blockers": [f"waiting_until_not_before:{not_before}"],
            "checks": [],
            **previous_runbook_fields,
        }

    checks: list[dict[str, Any]] = []
    if selected_step == "fresh_opra_live_scan":
        scan = current_report.get("scan") or {}
        quote_freshness = scan.get("quote_freshness_context") or {}
        retest_plan = scan.get("fresh_scan_retest_plan") or {}
        closest_liquidity = ((scan.get("gate_sensitivity") or {}).get("closest_option_liquidity")) or {}
        candidate_count = int(scan.get("candidate_count") or 0)
        freshness_status = quote_freshness.get("status")
        quote_age_excess = _number_or_none(
            retest_plan.get("primary_probe_quote_age_excess_hours")
            if retest_plan.get("primary_probe_quote_age_excess_hours") is not None
            else closest_liquidity.get("quote_age_excess_hours")
        )
        freshness_cleared = freshness_status not in {"stale_quote_sensitive", "stale_quote_blocked"}
        if quote_age_excess is None:
            quote_age_passed = freshness_cleared
            quote_age_actual: Any = freshness_status
        else:
            quote_age_passed = quote_age_excess <= 0
            quote_age_actual = quote_age_excess
        checks.extend(
            [
                _check_result("fresh_scan_candidate_count_above_zero", candidate_count > 0, actual=candidate_count, expected=">0"),
                _check_result(
                    "quote_freshness_status_not_stale_quote_sensitive_or_blocked",
                    freshness_cleared,
                    actual=freshness_status,
                    expected="not stale_quote_sensitive/stale_quote_blocked",
                ),
                _check_result(
                    "primary_probe_quote_age_excess_hours_at_or_below_zero",
                    quote_age_passed,
                    actual=quote_age_actual,
                    expected="<=0 or non-stale freshness status",
                ),
            ]
        )
    elif selected_step == "post_close_full_universe_capture":
        capture = current_report.get("capture") or {}
        gates = ((current_report.get("verification_gate") or {}).get("gates")) or {}
        exact_history = (
            current_report.get("exact_history_acquisition_plan")
            if isinstance(current_report.get("exact_history_acquisition_plan"), dict)
            else {}
        )
        exact_history_backfill_audit = (
            current_report.get("exact_history_backfill_capability_audit")
            if isinstance(current_report.get("exact_history_backfill_capability_audit"), dict)
            else exact_history.get("backfill_capability_audit")
            if isinstance(exact_history.get("backfill_capability_audit"), dict)
            else build_exact_history_backfill_capability_audit(current_report)
        )
        previous_shared_count = _int_from_nested(previous, "shared_quote_dates_after", "count")
        current_shared_count = _int_from_nested(current_report, "shared_quote_dates_after", "count")
        capture_complete = capture.get("target_capture_complete") is True
        shared_increased_or_complete = current_shared_count > previous_shared_count or (
            capture_complete and str(capture.get("status") or "") == "skipped_existing_shared_date"
        )
        hard_gates_pass = (
            gates.get("capture_scope_full_scan_universe") is True
            and gates.get("capture_target_complete") is True
            and gates.get("proof_scan_universe_aligned") is True
        )
        checks.extend(
            [
                _check_result("capture_target_complete_true", capture_complete, actual=capture.get("target_capture_complete"), expected=True),
                _check_result(
                    "shared_quote_dates_increase_or_target_was_already_complete",
                    shared_increased_or_complete,
                    actual={"previous": previous_shared_count, "current": current_shared_count, "capture_status": capture.get("status")},
                    expected="current > previous or existing complete target",
                ),
                _check_result(
                    "full_universe_hard_gates_remain_true",
                    hard_gates_pass,
                    actual={
                        "capture_scope_full_scan_universe": gates.get("capture_scope_full_scan_universe"),
                        "capture_target_complete": gates.get("capture_target_complete"),
                        "proof_scan_universe_aligned": gates.get("proof_scan_universe_aligned"),
                    },
                    expected=True,
                ),
                _check_result(
                    "local_exact_store_matches_proof_window_after_capture",
                    exact_history_backfill_audit.get("local_exact_store_matches_proof_window") is True,
                    actual=exact_history_backfill_audit.get("local_exact_store_matches_proof_window"),
                    expected=True,
                ),
                _check_result(
                    "local_exact_store_has_no_pending_refresh_after_capture",
                    exact_history_backfill_audit.get("local_exact_store_refresh_can_advance_history_depth") is not True,
                    actual=exact_history_backfill_audit.get("local_exact_store_refresh_can_advance_history_depth"),
                    expected=False,
                ),
            ]
        )
    else:
        return {
            "status": "unsupported_previous_step",
            "evaluated_at_utc": _utc_iso(current_ref),
            "previous_selected_step": selected_step,
            "previous_status": previous_contract.get("status"),
            "command": previous_contract.get("command"),
            "blockers": [f"unsupported_previous_step:{selected_step}"],
            "checks": [],
            **previous_runbook_fields,
        }

    failed = [check["name"] for check in checks if not check.get("passed")]
    return {
        "status": "passed" if not failed else "failed",
        "evaluated_at_utc": _utc_iso(current_ref),
        "previous_selected_step": selected_step,
        "previous_status": previous_contract.get("status"),
        "previous_not_before_utc": not_before,
        "command": previous_contract.get("command"),
        "success_criteria": previous_contract.get("success_criteria"),
        "checks": checks,
        "blockers": failed,
        **previous_runbook_fields,
    }


def next_blocker(
    *,
    readiness: dict[str, Any],
    replay: dict[str, Any] | None,
    scan: dict[str, Any] | None,
    min_shared_quote_dates: int,
    source_shared_quote_count: int | None = None,
    source_label: str | None = None,
) -> str:
    if source_shared_quote_count is None:
        shared_count = int(((readiness.get("shared_required_quote_dates") or {}).get("count")) or 0)
        blocker_prefix = "shared_quote_dates"
    else:
        shared_count = int(source_shared_quote_count or 0)
        label = str(source_label or "source").strip().lower().replace(" ", "_")
        blocker_prefix = f"{label}_shared_quote_dates"
    if shared_count < int(min_shared_quote_dates):
        return f"{blocker_prefix}:{shared_count}/{int(min_shared_quote_dates)}"
    if replay and replay.get("error"):
        return f"replay_error:{replay.get('error')}"
    if scan and int(scan.get("candidate_count") or 0) <= 0:
        drop_counts = (((scan.get("scan_funnel") or {}).get("drop_counts")) or {})
        dominant = max(drop_counts.items(), key=lambda item: int(item[1] or 0))[0] if drop_counts else "unknown"
        return f"scan_zero_candidates:{dominant}"
    if readiness.get("status") != "ready_for_exact_replay":
        return f"readiness:{readiness.get('blocker') or readiness.get('status')}"
    return "profitability_not_verified"


