def run_progress(
    *,
    symbols: list[str] | None = None,
    min_shared_quote_dates: int = DEFAULT_MIN_SHARED_QUOTE_DATES,
    db_path: Path | None = None,
    output_dir: Path = DEFAULT_OUTPUT_DIR,
    capture_output_dir: Path = DEFAULT_CAPTURE_OUTPUT_DIR,
    readiness_output_dir: Path = DEFAULT_READINESS_OUTPUT_DIR,
    lane_lab_output_dir: Path = DEFAULT_LANE_LAB_OUTPUT_DIR,
    force_capture: bool = False,
    skip_capture: bool = False,
    skip_replay: bool = False,
    skip_scan: bool = False,
    target_date: date | str | None = None,
    write: bool = True,
) -> dict[str, Any]:
    core_symbols = symbols or ai_commodity_scan_tickers()
    scan_symbols = ai_commodity_scan_tickers()
    capture_symbols = core_symbols if symbols is not None else scan_symbols
    resolved_db_path = Path(db_path) if db_path is not None else DEFAULT_HISTORICAL_DB_PATH
    os.environ["HISTORICAL_OPTIONS_DB_PATH"] = str(resolved_db_path)
    now = _utc_now()
    resolved_target_date = resolve_target_trade_date(
        now_utc=now,
        requested_target_date=target_date,
    )
    store = HistoricalOptionsStore(resolved_db_path)
    proof_source_labels = [ALPACA_OPRA_SOURCE_LABEL]
    shared_before = _shared_dates(store, core_symbols, source_labels=proof_source_labels)
    missing_target = symbols_missing_target_date(
        store,
        capture_symbols,
        resolved_target_date,
        source_labels=proof_source_labels,
    )

    capture: dict[str, Any] = {
        "status": "skipped",
        "target_date": resolved_target_date.isoformat(),
        "source_label_requirement": ALPACA_OPRA_SOURCE_LABEL,
        "scope": "ai_commodity_scan_universe" if capture_symbols == scan_symbols else "custom_symbols",
        "symbols": capture_symbols,
        "symbol_count": len(capture_symbols),
        "proof_symbol_count": len(core_symbols),
        "missing_target_date_symbols": missing_target,
        "shared_quote_dates_before": len(shared_before),
    }
    if skip_capture:
        capture["status"] = "skipped_by_request"
    elif not write:
        capture["status"] = "skipped_no_write"
        capture["write_guard"] = "no_write_disables_capture_and_import"
    elif not force_capture and not missing_target:
        capture["status"] = "skipped_existing_shared_date"
    else:
        if not alpaca_enabled():
            capture["status"] = "blocked_alpaca_not_enabled"
        elif str(os.getenv("ALPACA_OPTIONS_FEED") or "opra").strip().lower() != "opra":
            capture["status"] = "blocked_non_opra_feed"
        else:
            build = build_alpaca_opra_daily_snapshot(
                symbols=capture_symbols,
                target_date=resolved_target_date,
                min_dte=5,
                max_dte=60,
            )
            rows = list(build.pop("rows"))
            csv_path = _default_csv_path(
                Path(capture_output_dir),
                capture_symbols,
                date.fromisoformat(str(build["target_date"])),
            )
            import_result = None
            if rows:
                write_snapshot_csv(csv_path, rows)
                from historical_options_store import import_historical_option_snapshots

                import_result = import_historical_option_snapshots(
                    csv_path,
                    "alpaca_opra_daily_snapshot",
                    dataset_kind=DAILY_DATASET_KIND,
                    snapshot_kind=DAILY_SNAPSHOT_KIND,
                    db_path=resolved_db_path,
                )
            capture.update(
                {
                    **build,
                    "status": capture_status_from_import(rows, import_result),
                    "csv_path": str(csv_path) if rows else None,
                    "import_result": import_result,
                }
            )
            store = HistoricalOptionsStore(resolved_db_path)

    missing_target_after = symbols_missing_target_date(
        store,
        capture_symbols,
        resolved_target_date,
        source_labels=proof_source_labels,
    )
    capture["missing_target_date_symbols_after"] = missing_target_after
    capture["target_capture_complete"] = not missing_target_after
    shared_after = _shared_dates(store, core_symbols, source_labels=proof_source_labels)
    all_trusted_shared_after = _shared_dates(store, core_symbols)
    all_trusted_quote_date_counts = _date_counts_by_symbol(store, core_symbols)
    readiness = build_paid_data_readiness_audit(
        db_path=resolved_db_path,
        required_underlyings=core_symbols,
        snapshot_kind=DAILY_SNAPSHOT_KIND,
        min_quote_dates=int(min_shared_quote_dates),
        min_shared_quote_dates=int(min_shared_quote_dates),
        min_executable_quote_pct=90.0,
        source_labels=proof_source_labels,
    )
    if write:
        readiness_write = write_paid_data_readiness_audit(
            readiness,
            output_dir=Path(readiness_output_dir),
            force=True,
        )
        readiness_path_for_lane_lab = Path(readiness_write.get("latest") or Path(readiness_output_dir) / "latest.json")
        readiness_payload_for_lane_lab = None
    else:
        readiness_write = {
            "status": "skipped_no_write",
            "latest": None,
            "output_dir": str(Path(readiness_output_dir)),
        }
        readiness_path_for_lane_lab = Path(readiness_output_dir) / "latest.json"
        readiness_payload_for_lane_lab = readiness
    lane_lab = run_lane_lab(
        readiness_path=readiness_path_for_lane_lab,
        output_dir=Path(lane_lab_output_dir),
        write=write,
        readiness_payload=readiness_payload_for_lane_lab,
    )

    replay_summary: dict[str, Any] | None = None
    diagnostic_replay_summary: dict[str, Any] | None = None
    diagnostic_replay_max_dte = DEFAULT_DIAGNOSTIC_REPLAY_MAX_DTE
    diagnostic_required_quote_dates = diagnostic_replay_required_shared_quote_dates(
        int(min_shared_quote_dates),
        max_dte=diagnostic_replay_max_dte,
    )
    if not skip_replay:
        import wfo_optimizer as wfo

        diagnostic_replay_max_dte = diagnostic_replay_max_dte_from_wfo(wfo)
        diagnostic_required_quote_dates = diagnostic_replay_required_shared_quote_dates(
            int(min_shared_quote_dates),
            max_dte=diagnostic_replay_max_dte,
        )
        replay_summary = _replay_summary(
            wfo.run_historical_backtest(
                lookback_years=1,
                n_picks=1,
                iv_adj=1.0,
                pricing_lane="pessimistic",
                truth_lane="historical_imported_daily",
                playbook="ai_commodity_infra_observation",
                allowed_directions=["call", "put"],
                min_imported_calendar_dates=int(min_shared_quote_dates),
                save_result=bool(write),
            )
        )
        if 0 < len(shared_after) < int(min_shared_quote_dates):
            if len(shared_after) < diagnostic_required_quote_dates:
                diagnostic_replay_summary = build_diagnostic_replay_summary(
                    None,
                    current_shared_quote_dates=len(shared_after),
                    required_shared_quote_dates=int(min_shared_quote_dates),
                    diagnostic_min_imported_calendar_dates=diagnostic_required_quote_dates,
                    skipped_reason="insufficient_replay_simulation_quote_dates",
                )
            else:
                diagnostic_min_dates = max(diagnostic_required_quote_dates, len(shared_after))
                diagnostic_replay_summary = build_diagnostic_replay_summary(
                    _replay_summary(
                        wfo.run_historical_backtest(
                            lookback_years=1,
                            n_picks=1,
                            iv_adj=1.0,
                            pricing_lane="pessimistic",
                            truth_lane="historical_imported_daily",
                            playbook="ai_commodity_infra_observation",
                            allowed_directions=["call", "put"],
                            min_imported_calendar_dates=diagnostic_min_dates,
                            save_result=False,
                        )
                    ),
                    current_shared_quote_dates=len(shared_after),
                    required_shared_quote_dates=int(min_shared_quote_dates),
                    diagnostic_min_imported_calendar_dates=diagnostic_min_dates,
                )
        else:
            diagnostic_replay_summary = build_diagnostic_replay_summary(
                None,
                current_shared_quote_dates=len(shared_after),
                required_shared_quote_dates=int(min_shared_quote_dates),
                skipped_reason=(
                    "no_alpaca_opra_shared_quote_dates"
                    if len(shared_after) <= 0
                    else "full_replay_gate_has_required_shared_quote_dates"
                ),
            )
    else:
        diagnostic_replay_summary = build_diagnostic_replay_summary(
            None,
            current_shared_quote_dates=len(shared_after),
            required_shared_quote_dates=int(min_shared_quote_dates),
            skipped_reason="skip_replay_requested",
        )

    scan_summary: dict[str, Any] | None = None
    if not skip_scan:
        import options_chatbot as oc
        import supervised_scan as ss

        scan_summary = _scan_summary(
            ss.run_supervised_scan(
                scan_func=oc.scan_daily_top_trades,
                positions_repository=None,
                n_picks=3,
                watchlist_size=max(len(core_symbols), 24),
                playbook_id="ai_commodity_infra_observation",
                use_recommended_policy=False,
                include_blocked_guardrail_picks=True,
                enforce_portfolio_caps=False,
            )
        )
        scan_summary = annotate_scan_quote_freshness_timing(scan_summary, now_utc=now)

    proof_window = build_proof_window(
        shared_dates=shared_after,
        min_shared_quote_dates=min_shared_quote_dates,
        target_date=resolved_target_date,
        source_label=ALPACA_OPRA_SOURCE_LABEL,
        diagnostic_replay_max_dte=diagnostic_replay_max_dte,
        diagnostic_required_shared_quote_dates=diagnostic_required_quote_dates,
    )
    report = {
        "generated_at": _utc_iso(now),
        "provider": primary_provider_label(),
        "alpaca_enabled": alpaca_enabled(),
        "db_path": str(resolved_db_path),
        "symbols": core_symbols,
        "capture_symbols": capture_symbols,
        "shared_quote_dates_before": {
            "count": len(shared_before),
            "first": shared_before[0] if shared_before else None,
            "last": shared_before[-1] if shared_before else None,
        },
        "shared_quote_dates_after": {
            "count": len(shared_after),
            "first": shared_after[0] if shared_after else None,
            "last": shared_after[-1] if shared_after else None,
        },
        "quote_date_counts": _date_counts_by_symbol(store, core_symbols, source_labels=proof_source_labels),
        "proof_source_label": ALPACA_OPRA_SOURCE_LABEL,
        "all_trusted_shared_quote_dates_after": {
            "count": len(all_trusted_shared_after),
            "first": all_trusted_shared_after[0] if all_trusted_shared_after else None,
            "last": all_trusted_shared_after[-1] if all_trusted_shared_after else None,
        },
        "all_trusted_quote_date_counts": all_trusted_quote_date_counts,
        "proof_source_audit": build_proof_source_audit(
            store,
            core_symbols,
            proof_source_label=ALPACA_OPRA_SOURCE_LABEL,
        ),
        "commodity_research_lab": load_latest_commodity_research_lab(),
        "scan_proof_universe_alignment": build_scan_proof_universe_alignment(
            proof_symbols=core_symbols,
            scan_symbols=ai_commodity_scan_tickers(),
            scan=scan_summary,
        ),
        "proof_window": proof_window,
        "automation_health": load_capture_automation_health(),
        "source_quality": build_source_quality_summary(readiness),
        "capture": capture,
        "readiness": readiness,
        "readiness_artifact": readiness_write,
        "lane_lab_artifacts": lane_lab.get("artifacts"),
        "replay": replay_summary,
        "diagnostic_replay": diagnostic_replay_summary,
        "scan": scan_summary,
        "next_blocker": next_blocker(
            readiness=readiness,
            replay=replay_summary,
            scan=scan_summary,
            min_shared_quote_dates=min_shared_quote_dates,
            source_shared_quote_count=len(shared_after),
            source_label=ALPACA_OPRA_SOURCE_LABEL,
        ),
    }
    report["capture_action"] = build_capture_action_summary(report)
    report["exact_capture_import_health"] = build_exact_capture_import_health(report)
    report["verification_gate"] = build_verified_profitability_gate(report)
    report["proof_source_isolation_contract"] = build_proof_source_isolation_contract(report)
    report["alpaca_opra_data_usage_audit"] = build_alpaca_opra_data_usage_audit(report)
    report["lane_next_step"] = build_lane_next_step_summary(report)
    report["lane_iteration_plan"] = build_lane_iteration_plan(report)
    report["next_execution_contract"] = build_next_execution_contract(report)
    report["next_execution_preflight"] = build_next_execution_preflight(report, reference_now=now)
    previous_report = load_previous_progress_report(output_dir)
    report["last_execution_review"] = build_last_execution_review(previous_report, report)
    report["progress_delta"] = build_progress_delta(previous_report, report)
    report["previous_proof_event_outcome"] = build_previous_proof_event_outcome(previous_report, report)
    report["iteration_ledger"] = build_iteration_ledger(report)
    report["goal_completion_audit"] = build_goal_completion_audit(report)
    report["fresh_scan_iteration_decision"] = build_fresh_scan_iteration_decision(report)
    runbook_payload = build_next_execution_cli_payload(
        report,
        payload_source="current_run",
        reference_now=now,
    )
    report["next_execution_runbook_card"] = runbook_payload.get("next_execution_runbook_card")
    report["next_execution_runbook_snapshot"] = {
        "payload_source": runbook_payload.get("payload_source"),
        "generated_at": runbook_payload.get("generated_at"),
        "read_at_utc": runbook_payload.get("read_at_utc"),
        "clock_status": runbook_payload.get("next_execution_clock_status"),
        "due_by_clock": runbook_payload.get("next_execution_due_by_clock"),
        "expired_by_clock": runbook_payload.get("next_execution_expired_by_clock"),
        "recommended_action": runbook_payload.get("next_execution_recommended_action"),
        "effective_actionable_now": runbook_payload.get("next_execution_effective_actionable_now"),
        "wait_minutes": runbook_payload.get("next_execution_wait_minutes"),
        "window_minutes_remaining": runbook_payload.get("next_execution_window_minutes_remaining"),
    }
    report["exact_history_acquisition_plan"] = build_exact_history_acquisition_plan(report)
    report["exact_history_backfill_capability_audit"] = report["exact_history_acquisition_plan"].get(
        "backfill_capability_audit"
    )
    report = attach_last_execution_local_store_evidence(report)
    report["goal_completion_evidence_plan"] = build_goal_completion_evidence_plan(report)
    report["exact_capture_post_run_evaluation"] = build_exact_capture_post_run_evaluation(report)
    report["exact_capture_progress_contract"] = build_exact_capture_progress_contract(report)
    report["exact_capture_progress_outcome"] = build_exact_capture_progress_outcome(previous_report, report)
    report["fresh_scan_iteration_decision"] = build_fresh_scan_iteration_decision(report)
    report["fresh_scan_post_run_evaluation"] = build_fresh_scan_post_run_evaluation(report)
    report["previous_proof_event_outcome"] = build_previous_proof_event_outcome(previous_report, report)
    report = attach_previous_proof_event_local_store_evidence(report)
    report["iteration_ledger"] = build_iteration_ledger(report)
    report["post_fresh_scan_research_backlog"] = build_post_fresh_scan_research_backlog(report)
    report = attach_deferred_variant_result_collection(report, force=True)
    report["exact_replay_unlock_contract"] = build_exact_replay_unlock_contract(report)
    report["exact_replay_smoke_probe_plan"] = build_exact_replay_smoke_probe_plan(report, output_dir=output_dir)
    report["exact_replay_runway_progress"] = build_exact_replay_runway_progress_contract(report)
    report["live_candidate_recovery_plan"] = build_live_candidate_recovery_plan(report)
    report["exact_profitability_blocker_review"] = build_exact_profitability_blocker_review(report)
    report["next_proof_event_checkpoint"] = build_next_proof_event_checkpoint(report)
    report["lane_next_step_plan"] = build_lane_next_step_plan(report)
    report["guarded_capture_runbook_packet"] = build_guarded_capture_runbook_packet(report)
    report["auxiliary_proof_event_queue"] = build_auxiliary_proof_event_queue(report)
    report["raw_drop_reason_evidence_contract"] = build_raw_drop_reason_evidence_contract(report)
    report["next_profitability_evidence_sequence"] = build_next_profitability_evidence_sequence(report)
    report["profitability_evidence_scorecard"] = build_profitability_evidence_scorecard(report)
    report["profitability_evidence_scorecard_delta"] = build_profitability_evidence_scorecard_delta(
        previous_report,
        report,
    )
    report["previous_auxiliary_proof_event_outcome"] = (
        build_previous_auxiliary_proof_event_outcome(previous_report, report)
    )
    report["iteration_ledger"] = build_iteration_ledger(report)
    report["goal_completion_verification_contract"] = build_goal_completion_verification_contract(report)
    attach_progress_record_summary_fields(report)
    if write:
        report["artifacts"] = write_progress_report(report, output_dir)
    return report


def build_strict_accuracy_gate(report: dict[str, Any]) -> dict[str, Any]:
    verification = report.get("verification_gate") if isinstance(report.get("verification_gate"), dict) else {}
    proof_window = report.get("proof_window") if isinstance(report.get("proof_window"), dict) else {}
    audit = report.get("goal_completion_audit") if isinstance(report.get("goal_completion_audit"), dict) else {}
    if not audit:
        audit = build_goal_completion_audit(report)
    contract = (
        report.get("goal_completion_verification_contract")
        if isinstance(report.get("goal_completion_verification_contract"), dict)
        else {}
    )
    if not contract:
        contract = build_goal_completion_verification_contract({**report, "goal_completion_audit": audit})
    current_shared_quote_dates = _int_or_zero(proof_window.get("current_shared_quote_dates"))
    requested_shared_quote_dates = _int_or_zero(
        proof_window.get("required_shared_quote_dates") or DEFAULT_MIN_SHARED_QUOTE_DATES
    )
    exact_history_depth_floor = {
        "current_shared_quote_dates": current_shared_quote_dates,
        "required_shared_quote_dates": proof_window.get("required_shared_quote_dates"),
        "requested_required_shared_quote_dates": requested_shared_quote_dates,
        "default_required_shared_quote_dates_floor": DEFAULT_MIN_SHARED_QUOTE_DATES,
        "effective_goal_required_shared_quote_dates": max(
            requested_shared_quote_dates,
            DEFAULT_MIN_SHARED_QUOTE_DATES,
        ),
        "exact_history_depth_floor_satisfied": (
            current_shared_quote_dates >= DEFAULT_MIN_SHARED_QUOTE_DATES
        ),
    }
    floor_blockers = []
    if exact_history_depth_floor.get("exact_history_depth_floor_satisfied") is not True:
        floor_blockers.append("exact_history_depth_floor_not_satisfied")
    unproven_requirements = _unique_strings(
        [
            contract.get("unproven_requirements"),
            audit.get("failed_requirements"),
            (
                ["has_required_exact_alpaca_opra_history_depth"]
                if floor_blockers
                else []
            ),
        ]
    )
    passed = contract.get("completion_claim_allowed") is True and not floor_blockers
    blockers = _unique_strings(
        [
            verification.get("blockers"),
            audit.get("blockers"),
            contract.get("unproven_requirements"),
            floor_blockers,
            report.get("next_blocker"),
        ]
    )
    return {
        "status": "passed" if passed else "failed",
        "passed": passed,
        "verification_status": verification.get("status"),
        "verification_verified": verification.get("verified"),
        "goal_completion_status": audit.get("status"),
        "completion_claim_allowed": passed,
        "unproven_requirements": unproven_requirements,
        "blockers": blockers,
        "exact_history_depth_floor": exact_history_depth_floor,
        "next_evidence_action": contract.get("next_evidence_action") or audit.get("next_action"),
        "next_evidence_command": contract.get("next_evidence_command"),
    }


def attach_strict_accuracy_gate(report: dict[str, Any]) -> dict[str, Any]:
    strict_gate = report.get("strict_accuracy_gate")
    if not isinstance(strict_gate, dict):
        strict_gate = build_strict_accuracy_gate(report)
        report["strict_accuracy_gate"] = strict_gate
    return strict_gate


def strict_accuracy_gate_exit_code(report: dict[str, Any], *, enabled: bool) -> int:
    if not enabled:
        return 0
    strict_gate = attach_strict_accuracy_gate(report)
    return 0 if strict_gate.get("passed") is True else 2


def main() -> int:
    parser = argparse.ArgumentParser(
        description="Advance the AI commodity lane proof loop with Alpaca OPRA capture, readiness, replay, and scan evidence."
    )
    parser.add_argument("--env-file", default=str(ROOT / ".env.local"))
    parser.add_argument("--db-path", help="Historical options SQLite path override.")
    parser.add_argument("--output-dir", default=str(DEFAULT_OUTPUT_DIR))
    parser.add_argument("--capture-output-dir", default=str(DEFAULT_CAPTURE_OUTPUT_DIR))
    parser.add_argument("--readiness-output-dir", default=str(DEFAULT_READINESS_OUTPUT_DIR))
    parser.add_argument("--lane-lab-output-dir", default=str(DEFAULT_LANE_LAB_OUTPUT_DIR))
    parser.add_argument("--min-shared-quote-dates", type=int, default=DEFAULT_MIN_SHARED_QUOTE_DATES)
    parser.add_argument("--target-date", help="Explicit US equity market trade date to capture/report, YYYY-MM-DD.")
    parser.add_argument("--force-capture", action="store_true")
    parser.add_argument("--skip-capture", action="store_true")
    parser.add_argument("--skip-replay", action="store_true")
    parser.add_argument("--skip-scan", action="store_true")
    parser.add_argument("--no-write", action="store_true")
    parser.add_argument(
        "--strict-gate",
        action="store_true",
        help="Exit nonzero unless the generated report proves the full accuracy/completion contract.",
    )
    parser.add_argument(
        "--record-smoke-probe-observation",
        action="store_true",
        help=(
            "Write only a non-verifying exact replay smoke-probe observation artifact. "
            "Requires --no-write --skip-capture --skip-scan and cannot satisfy profitability gates."
        ),
    )
    parser.add_argument(
        "--next-execution",
        action="store_true",
        help="Print only the next execution contract, last execution review, and verification blockers.",
    )
    parser.add_argument(
        "--from-latest",
        action="store_true",
        help=(
            "With --next-execution, read latest.json and deterministically refresh local DB/runbook fields "
            "without running a fresh progress cycle."
        ),
    )
    parser.add_argument(
        "--refresh-derived-from-latest",
        action="store_true",
        help=(
            "Recompute deterministic proof/runbook fields from latest.json without running scans, capture, or replay."
        ),
    )
    parser.add_argument(
        "--materialize-deferred-variant-configs",
        action="store_true",
        help=(
            "Write deferred research variant config JSON files from latest.json only after exact OPRA activation "
            "gates and recipe audits pass."
        ),
    )
    parser.add_argument(
        "--materialize-dry-run",
        action="store_true",
        help="With --materialize-deferred-variant-configs, validate and report paths without writing config files.",
    )
    parser.add_argument(
        "--collect-deferred-variant-results",
        action="store_true",
        help="Collect and rank completed exact-OPRA deferred variant sweep results from research_runs.",
    )
    parser.add_argument(
        "--run-deferred-variant-sweeps",
        action="store_true",
        help="Materialize and run ordered deferred exact-OPRA variant sweeps after activation gates pass.",
    )
    parser.add_argument(
        "--deferred-variant-sweep-dry-run",
        action="store_true",
        help="With --run-deferred-variant-sweeps, validate and print sweep commands without executing them.",
    )
    parser.add_argument(
        "--deferred-variant-sweep-limit",
        type=int,
        help="With --run-deferred-variant-sweeps, execute at most this many ordered sweeps.",
    )
    parser.add_argument("--json", action="store_true")
    args = parser.parse_args()

    if args.record_smoke_probe_observation:
        if not args.no_write or not args.skip_capture or not args.skip_scan:
            parser.error(
                "--record-smoke-probe-observation requires --no-write --skip-capture --skip-scan."
            )
        if args.skip_replay:
            parser.error("--record-smoke-probe-observation cannot be used with --skip-replay.")

    if args.run_deferred_variant_sweeps:
        reference_now = _utc_now()
        latest_report = load_previous_progress_report(Path(args.output_dir))
        if latest_report is None:
            parser.error(f"No latest progress report found in {Path(args.output_dir)}.")
        report = refresh_derived_fields_from_latest(
            latest_report,
            reference_now=reference_now,
            refresh_automation_health=True,
        )
        result = run_deferred_variant_sweeps(
            report,
            root=ROOT,
            dry_run=bool(args.deferred_variant_sweep_dry_run or args.no_write),
            max_sweeps=args.deferred_variant_sweep_limit,
        )
        print(json.dumps(result, indent=2))
        return 1 if result.get("status") == "variant_sweep_failed" else 0

    if args.collect_deferred_variant_results:
        reference_now = _utc_now()
        latest_report = load_previous_progress_report(Path(args.output_dir))
        if latest_report is None:
            parser.error(f"No latest progress report found in {Path(args.output_dir)}.")
        report = refresh_derived_fields_from_latest(
            latest_report,
            reference_now=reference_now,
            refresh_automation_health=True,
        )
        result = collect_deferred_variant_results(report, root=ROOT)
        print(json.dumps(result, indent=2))
        return 0

    if args.materialize_deferred_variant_configs:
        reference_now = _utc_now()
        latest_report = load_previous_progress_report(Path(args.output_dir))
        if latest_report is None:
            parser.error(f"No latest progress report found in {Path(args.output_dir)}.")
        report = refresh_derived_fields_from_latest(
            latest_report,
            reference_now=reference_now,
            refresh_automation_health=True,
        )
        result = materialize_deferred_variant_configs(
            report,
            root=ROOT,
            dry_run=bool(args.materialize_dry_run or args.no_write),
        )
        print(json.dumps(result, indent=2))
        return 0

    if args.refresh_derived_from_latest:
        reference_now = _utc_now()
        latest_report = load_previous_progress_report(Path(args.output_dir))
        if latest_report is None:
            parser.error(f"No latest progress report found in {Path(args.output_dir)}.")
        report = refresh_derived_fields_from_latest(
            latest_report,
            reference_now=reference_now,
            refresh_automation_health=True,
        )
        if args.strict_gate:
            attach_strict_accuracy_gate(report)
        if not args.no_write:
            report["artifacts"] = write_progress_report(report, Path(args.output_dir))
        if args.next_execution:
            print(
                json.dumps(
                    build_next_execution_cli_payload(
                        report,
                        payload_source="derived_latest_refresh",
                        reference_now=reference_now,
                    ),
                    indent=2,
                )
            )
        elif args.json:
            print(json.dumps(report, indent=2))
        else:
            summary = build_compact_progress_summary(report)
            if args.strict_gate:
                summary["strict_accuracy_gate"] = report.get("strict_accuracy_gate")
            print(json.dumps(summary, indent=2))
        return strict_accuracy_gate_exit_code(report, enabled=bool(args.strict_gate))

    if args.from_latest:
        if not args.next_execution:
            parser.error("--from-latest is only supported with --next-execution.")
        reference_now = _utc_now()
        latest_report = load_previous_progress_report(Path(args.output_dir))
        if latest_report is None:
            parser.error(f"No latest progress report found in {Path(args.output_dir)}.")
        report = refresh_derived_fields_from_latest(
            latest_report,
            reference_now=reference_now,
            refresh_automation_health=True,
        )
        if args.strict_gate:
            attach_strict_accuracy_gate(report)
        print(
            json.dumps(
                build_next_execution_cli_payload(
                    report,
                    payload_source="latest_artifact",
                    reference_now=reference_now,
                ),
                indent=2,
            )
        )
        return strict_accuracy_gate_exit_code(report, enabled=bool(args.strict_gate))

    load_env_file(Path(args.env_file))
    os.environ.setdefault("OPTIONS_MARKET_DATA_PROVIDER", "alpaca")
    os.environ.setdefault("ALPACA_STOCK_FEED", "sip")
    os.environ.setdefault("ALPACA_OPTIONS_FEED", "opra")
    if args.db_path:
        os.environ["HISTORICAL_OPTIONS_DB_PATH"] = str(Path(args.db_path))
    else:
        os.environ["HISTORICAL_OPTIONS_DB_PATH"] = str(DEFAULT_HISTORICAL_DB_PATH)

    try:
        requested_target_date = parse_target_trade_date(args.target_date)
        report = run_progress(
            min_shared_quote_dates=int(args.min_shared_quote_dates),
            db_path=Path(args.db_path) if args.db_path else DEFAULT_HISTORICAL_DB_PATH,
            output_dir=Path(args.output_dir),
            capture_output_dir=Path(args.capture_output_dir),
            readiness_output_dir=Path(args.readiness_output_dir),
            lane_lab_output_dir=Path(args.lane_lab_output_dir),
            force_capture=bool(args.force_capture),
            skip_capture=bool(args.skip_capture),
            skip_replay=bool(args.skip_replay),
            skip_scan=bool(args.skip_scan),
            target_date=requested_target_date,
            write=not bool(args.no_write),
        )
    except ValueError as exc:
        parser.error(str(exc))
    if args.record_smoke_probe_observation:
        smoke_command = (
            "python scripts/run_ai_commodity_opra_progress.py --skip-capture --skip-scan "
            f"--min-shared-quote-dates {int(args.min_shared_quote_dates)} "
            "--no-write --record-smoke-probe-observation --json"
        )
        observation = build_exact_replay_smoke_probe_observation(
            report,
            min_shared_quote_dates=int(args.min_shared_quote_dates),
            command=smoke_command,
        )
        artifacts = write_exact_replay_smoke_probe_observation(observation, Path(args.output_dir))
        report["exact_replay_smoke_probe_observation"] = {**observation, "artifacts": artifacts}
        report["exact_replay_smoke_probe_observation_path"] = artifacts["latest_json"]
        report["exact_replay_smoke_probe_observation_status"] = observation.get("status")
        report["exact_replay_smoke_probe_plan"] = build_exact_replay_smoke_probe_plan(
            report,
            output_dir=Path(args.output_dir),
        )
        report["exact_replay_runway_progress"] = build_exact_replay_runway_progress_contract(report)
        report["next_profitability_evidence_sequence"] = build_next_profitability_evidence_sequence(report)
        report["profitability_evidence_scorecard"] = build_profitability_evidence_scorecard(report)
        report["profitability_evidence_scorecard_delta"] = build_profitability_evidence_scorecard_delta(
            None,
            report,
        )
        attach_progress_record_summary_fields(report)
    if args.next_execution:
        print(json.dumps(build_next_execution_cli_payload(report, payload_source="current_run"), indent=2))
    elif args.json:
        if args.strict_gate:
            attach_strict_accuracy_gate(report)
        print(json.dumps(report, indent=2))
    else:
        summary = build_compact_progress_summary(report)
        if args.strict_gate:
            summary["strict_accuracy_gate"] = attach_strict_accuracy_gate(report)
        print(json.dumps(summary, indent=2))
    return strict_accuracy_gate_exit_code(report, enabled=bool(args.strict_gate))


if __name__ == "__main__":
    raise SystemExit(main())
